// === INJETAR BOTÃO DE GERAR CARD DENTRO DA ABA INFO ===
function injetarBotaoGerarCard(establishment, containerInfo) {
  if (!containerInfo) return;

  const estId = establishment.nomeNormalizado || normalizeName(establishment.name || "");

  const box = document.createElement("div");
  box.className = "info-box";

  box.innerHTML = `
        <button class="btn-gerar-card"
                data-estab-id="${estId}">
            <i class="fa-solid fa-image"></i> Gerar card para divulgação
        </button>
    `;

  containerInfo.appendChild(box);
}




// Responsável do imóvel mesmo sem "corretor" explícito
function getResponsavelImovel(im) {
  // Se já houver util oficial, prioriza
  if (typeof getCorretorPrincipal === "function") {
    const c = getCorretorPrincipal(im);
    if (c) return c;
  }
  // Fallbacks comuns de dados
  return (
    im.proprietario ||
    im.dono ||
    (Array.isArray(im.corretores) && im.corretores.length ? im.corretores[0] : "") ||
    im.corretor ||
    "Proprietário não informado"
  );
}


function getHojeBR() {
  const parts = new Intl.DateTimeFormat("pt-BR", {
    timeZone: "America/Sao_Paulo",
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(new Date());
  const values = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  return `${values.year}-${values.month}-${values.day}`;
}

function normalizarChaveMetricaCliente(valor) {
  return String(valor || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]/g, "");
}

function resolverChaveMetricaCliente(idEstabelecimento) {
  const original = String(idEstabelecimento || "").trim();
  const normalized = normalizarChaveMetricaCliente(original);
  const mapped = variantesChaveMetricaCliente(original)
    .map(normalizarChaveMetricaCliente)
    .map((key) => window.__metricClientIds?.[key])
    .find(Boolean);
  if (mapped) return mapped;

  const metricClientIds = window.__metricClientIds || {};
  const fuzzyMatch = Object.entries(metricClientIds)
    .filter(([key]) => {
      const normalizedKey = normalizarChaveMetricaCliente(key);
      return normalizedKey.length > 3 && normalized.length > 3
        && (normalized.includes(normalizedKey) || normalizedKey.includes(normalized));
    })
    .sort((a, b) => String(b[0]).length - String(a[0]).length)[0];
  return fuzzyMatch?.[1] || normalized;
}

function escaparArteComercial(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function textoLimpoArteComercial(value) {
  const holder = document.createElement("div");
  holder.innerHTML = String(value || "");
  return String(holder.textContent || holder.innerText || "").replace(/\s+/g, " ").trim();
}

function normalizarArteComercial(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function valorPreenchidoArteComercial(value) {
  const text = textoLimpoArteComercial(value);
  return /^(?:-|--|nao informado|não informado|nao possui|não possui|n\/a)$/i.test(text) ? "" : text;
}

function urlAbsolutaArteComercial(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  try {
    return new URL(raw, window.location.href).href;
  } catch (error) {
    return raw;
  }
}

function aguardarImagensArteComercial(root) {
  return Promise.all([...root.querySelectorAll("img")].map((img) => {
    if (img.complete) return Promise.resolve();
    return new Promise((resolve) => {
      img.addEventListener("load", resolve, { once: true });
      img.addEventListener("error", resolve, { once: true });
    });
  }));
}

async function detectarEnquadramentoArteComercial(imageUrl, configured = "auto") {
  if (["contain", "cover"].includes(configured)) return configured;
  if (!imageUrl) return "contain";
  const fileHint = String(imageUrl).toLowerCase();
  if (/logo|perfil|profile|marca|icone|icon/.test(fileHint)) return "contain";
  return new Promise((resolve) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const ratio = img.naturalWidth / Math.max(1, img.naturalHeight);
      resolve(ratio > 1.45 || ratio < 0.7 ? "contain" : "cover");
    };
    img.onerror = () => resolve("contain");
    img.src = imageUrl;
  });
}

async function capturarFundoSiteArteComercial() {
  if (typeof html2canvas !== "function") return "";
  document.body.classList.add("business-art-capturing-background");
  try {
    const canvas = await html2canvas(document.body, {
      width: window.innerWidth,
      height: window.innerHeight,
      windowWidth: window.innerWidth,
      windowHeight: window.innerHeight,
      scrollX: 0,
      scrollY: 0,
      scale: Math.min(1.35, window.devicePixelRatio || 1),
      useCORS: true,
      allowTaint: false,
      logging: false,
      backgroundColor: "#eef4ff",
      ignoreElements: (element) => element.classList?.contains("business-art-dialog")
    });
    return canvas.toDataURL("image/jpeg", 0.86);
  } catch (error) {
    console.warn("Nao foi possivel capturar o fundo atual do site.", error);
    return "";
  } finally {
    document.body.classList.remove("business-art-capturing-background");
  }
}

async function prepararImagemArteComercial(imageUrl) {
  const source = urlAbsolutaArteComercial(imageUrl);
  if (!source || source.startsWith("data:")) return source;
  const blobToDataUrl = (blob) => new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
  const fetchAsDataUrl = async (url) => {
    const response = await fetch(url, { mode: "cors", cache: "force-cache" });
    if (!response.ok) throw new Error(`Imagem indisponivel (${response.status})`);
    const blob = await response.blob();
    if (!String(blob.type || "").toLowerCase().startsWith("image/")) throw new Error("Resposta nao e uma imagem");
    return blobToDataUrl(blob);
  };
  try {
    return await fetchAsDataUrl(source);
  } catch (directError) {
    try {
      const parsed = new URL(source);
      if (!["firebasestorage.googleapis.com", "storage.googleapis.com"].includes(parsed.hostname)) return source;
      const proxyPath = `/.netlify/functions/image-proxy?url=${encodeURIComponent(source)}`;
      const proxyCandidates = [proxyPath];
      if (["localhost", "127.0.0.1", "::1"].includes(window.location.hostname)) {
        proxyCandidates.push(`https://www.olacarlopolis.com${proxyPath}`);
      }
      for (const proxyUrl of proxyCandidates) {
        try {
          return await fetchAsDataUrl(proxyUrl);
        } catch (proxyCandidateError) {
          // Tenta a proxima rota de proxy disponivel.
        }
      }
      throw new Error("Nenhum proxy de imagem respondeu.");
    } catch (proxyError) {
      console.warn("Nao foi possivel preparar a imagem de perfil para a arte.", directError, proxyError);
      return source;
    }
  }
}

function dadosArteComercial(establishment = {}, categoriaAtual = "") {
  const contatos = getContatosDetalhadosEstabelecimento(establishment);
  const whatsapp = contatos.find((item) => item.whatsapp)?.numero
    || establishment.whatsapp
    || contatos[0]?.numero
    || establishment.contact
    || establishment.contato
    || "";
  const imagens = [
    establishment.image,
    establishment.imagem,
    establishment.logo,
    ...(Array.isArray(establishment.novidadesImages) ? establishment.novidadesImages : []),
    ...(Array.isArray(establishment.divulgacaoImages) ? establishment.divulgacaoImages : [])
  ].filter(Boolean);
  const tipo = normalizarArteComercial(establishment.tipoCliente || establishment.tipo || "comercio");
  const tipoLabel = tipo === "servico" || tipo === "servicos"
    ? "Serviço"
    : (tipo === "institucional" ? "Institucional" : "Comércio");
  const descricao = establishment.descricaoCurta
    || establishment.shortDescription
    || establishment.descricao
    || establishment.description
    || establishment.infoAdicional
    || (Array.isArray(establishment.novidadesDescriptions) ? establishment.novidadesDescriptions.find(Boolean) : "")
    || "";
  return {
    nome: textoLimpoArteComercial(establishment.name || establishment.nome || establishment.title || "Estabelecimento"),
    descricao: textoLimpoArteComercial(descricao).slice(0, 220),
    categoria: textoLimpoArteComercial(categoriaAtual || establishment.categoria || establishment.category || ""),
    tipoLabel,
    whatsapp: formatarTelefonePublico(whatsapp),
    cidade: valorPreenchidoArteComercial(establishment.cidade || establishment.city || establishment.localidade || "Carlópolis - PR"),
    endereco: valorPreenchidoArteComercial(establishment.address || establishment.endereco || ""),
    imagem: urlAbsolutaArteComercial(imagens[0] || ""),
    imagemEnquadramento: establishment.imagemEnquadramento || establishment.imageFit || "auto"
  };
}

function montarConteudoArteComercial({ dados, formato, fundoUrl, logoSiteUrl, imageFit }) {
  const imageBlock = dados.imagem
    ? `<img class="business-art-main-image" src="${escaparArteComercial(dados.imagem)}" alt="" crossorigin="anonymous" style="object-fit:${imageFit}">`
    : `<div class="business-art-placeholder"><i class="fa-solid fa-store"></i><span>${escaparArteComercial(dados.categoria || dados.tipoLabel)}</span></div>`;
  const contactCards = [
    dados.whatsapp ? `<div class="business-art-info-card"><i class="fa-brands fa-whatsapp"></i><span><small>WhatsApp</small><strong>${escaparArteComercial(dados.whatsapp)}</strong></span></div>` : "",
    dados.cidade ? `<div class="business-art-info-card"><i class="fa-solid fa-location-dot"></i><span><small>Cidade</small><strong>${escaparArteComercial(dados.cidade)}</strong></span></div>` : ""
  ].filter(Boolean);
  const background = fundoUrl
    ? `background-image:url('${fundoUrl}');`
    : "background:linear-gradient(145deg,#e6efff 0%,#ffffff 44%,#dbeafe 100%);";

  return `
    <div class="business-art-background" style="${background}"></div>
    <div class="business-art-shade"></div>
    <article class="business-art-card">
      <header class="business-art-header">
        <span class="business-art-kind"><i class="fa-solid fa-store"></i>${escaparArteComercial(dados.tipoLabel)}</span>
        ${dados.categoria ? `<strong>${escaparArteComercial(dados.categoria)}</strong>` : ""}
      </header>
      <div class="business-art-picture is-${imageFit}">${imageBlock}</div>
      <section class="business-art-identity">
        <h1>${escaparArteComercial(dados.nome)}</h1>
        <span class="business-art-name-line"></span>
        ${dados.descricao ? `<p>${escaparArteComercial(dados.descricao)}</p>` : ""}
      </section>
      ${(contactCards.length || dados.endereco) ? `
        <section class="business-art-info">
          ${contactCards.length ? `<div class="business-art-info-grid ${contactCards.length === 1 ? "is-single" : ""}">${contactCards.join("")}</div>` : ""}
          ${dados.endereco ? `<div class="business-art-info-card is-address"><i class="fa-solid fa-map-location-dot"></i><span><small>Endereço</small><strong>${escaparArteComercial(dados.endereco)}</strong></span></div>` : ""}
        </section>` : ""}
      <footer class="business-art-footer">
        <div><i class="fa-solid fa-globe"></i><span><small>Encontre no</small><strong>www.olacarlopolis.com</strong></span></div>
        <span class="business-art-brand-logo"><img src="${escaparArteComercial(logoSiteUrl)}" alt="Ola Carlopolis" crossorigin="anonymous"></span>
      </footer>
    </article>
    <div class="business-art-disclaimer"><i class="fa-solid fa-lock"></i> Informações fornecidas pelo estabelecimento.</div>
  `;
}

async function gerarImagemCardEstabelecimento(establishment, categoriaAtual, slugId) {
  if (!establishment || document.querySelector(".business-art-dialog")) return;
  if (typeof html2canvas !== "function") {
    mostrarToast("O gerador de imagens ainda esta carregando. Tente novamente.");
    return;
  }

  mostrarToast("Preparando a previa da arte...");
  const dados = dadosArteComercial(establishment, categoriaAtual);
  const [fundoUrl, imageFit, imagemPreparada] = await Promise.all([
    capturarFundoSiteArteComercial(),
    detectarEnquadramentoArteComercial(
      dados.imagem,
      establishment.imagemEnquadramento || establishment.imageFit || "auto"
    ),
    prepararImagemArteComercial(dados.imagem)
  ]);
  if (imagemPreparada) dados.imagem = imagemPreparada;
  const logoSiteUrl = urlAbsolutaArteComercial("images/img_padrao_site/logo_1.png");
  const dialog = document.createElement("div");
  dialog.className = "business-art-dialog";
  dialog.setAttribute("role", "dialog");
  dialog.setAttribute("aria-modal", "true");
  dialog.setAttribute("aria-label", "Pre-visualizacao da arte do estabelecimento");
  dialog.innerHTML = `
    <div class="business-art-panel">
      <div class="business-art-toolbar">
        <div><strong>Arte para divulgacao</strong><small>Escolha o formato e confira antes de baixar.</small></div>
        <div class="business-art-format" role="group" aria-label="Formato da imagem">
          <button type="button" data-business-format="story">Story <small>1080 x 1920</small></button>
          <button type="button" class="active" data-business-format="feed">Feed <small>1080 x 1350</small></button>
        </div>
        <button type="button" class="business-art-close" aria-label="Fechar"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div class="business-art-preview"><div class="business-art-scale"><div class="business-art-stage is-feed"></div></div></div>
      <div class="business-art-actions">
        <span class="business-art-resolution">PNG 1080 x 1350</span>
        <button type="button" class="business-art-download"><i class="fa-solid fa-download"></i> Baixar imagem</button>
      </div>
    </div>`;

  const previousOverflow = document.documentElement.style.overflow;
  document.documentElement.style.overflow = "hidden";
  document.body.appendChild(dialog);
  const stage = dialog.querySelector(".business-art-stage");
  const scaleBox = dialog.querySelector(".business-art-scale");
  const preview = dialog.querySelector(".business-art-preview");
  let formato = "feed";

  const render = async () => {
    const height = formato === "story" ? 1920 : 1350;
    stage.className = `business-art-stage is-${formato}`;
    stage.style.width = "1080px";
    stage.style.height = `${height}px`;
    stage.innerHTML = montarConteudoArteComercial({ dados, formato, fundoUrl, logoSiteUrl, imageFit });
    dialog.querySelector(".business-art-resolution").textContent = `PNG 1080 x ${height}`;
    await aguardarImagensArteComercial(stage);
    const card = stage.querySelector(".business-art-card");
    const disclaimer = stage.querySelector(".business-art-disclaimer");
    if (card && disclaimer) {
      disclaimer.style.top = `${Math.min(height - 58, card.offsetTop + card.offsetHeight + 24)}px`;
      disclaimer.style.bottom = "auto";
    }
    requestAnimationFrame(resize);
  };

  const resize = () => {
    const height = formato === "story" ? 1920 : 1350;
    const availableWidth = Math.max(240, preview.clientWidth - 24);
    const availableHeight = Math.max(320, Math.min(window.innerHeight * 0.7, preview.clientHeight || window.innerHeight * 0.7) - 24);
    const scale = Math.min(availableWidth / 1080, availableHeight / height);
    scaleBox.style.width = `${1080 * scale}px`;
    scaleBox.style.height = `${height * scale}px`;
    scaleBox.style.transform = "none";
    stage.style.transform = `scale(${scale})`;
    stage.style.transformOrigin = "top left";
  };

  const close = () => {
    window.removeEventListener("resize", resize);
    document.removeEventListener("keydown", closeOnEscape);
    document.documentElement.style.overflow = previousOverflow;
    dialog.remove();
  };

  dialog.querySelectorAll("[data-business-format]").forEach((button) => {
    button.addEventListener("click", async () => {
      formato = button.dataset.businessFormat;
      dialog.querySelectorAll("[data-business-format]").forEach((item) => item.classList.toggle("active", item === button));
      await render();
    });
  });
  dialog.querySelector(".business-art-close").addEventListener("click", close);
  dialog.addEventListener("click", (event) => { if (event.target === dialog) close(); });
  window.addEventListener("resize", resize);
  document.addEventListener("keydown", function closeOnEscape(event) {
    if (event.key !== "Escape" || !dialog.isConnected) return;
    document.removeEventListener("keydown", closeOnEscape);
    close();
  });
  dialog.querySelector(".business-art-download").addEventListener("click", async (event) => {
    const button = event.currentTarget;
    const original = button.innerHTML;
    let exportHost = null;
    button.disabled = true;
    button.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Gerando PNG...';
    try {
      await aguardarImagensArteComercial(stage);
      if (document.fonts?.ready) await document.fonts.ready;
      const height = formato === "story" ? 1920 : 1350;

      // O preview fica dentro de um contêiner reduzido e com overflow. Renderizar
      // o próprio elemento ali faz o html2canvas herdar esse recorte. A cópia
      // isolada preserva o layout real de 1080 px sem interferência da modal.
      exportHost = document.createElement("div");
      exportHost.setAttribute("aria-hidden", "true");
      Object.assign(exportHost.style, {
        position: "fixed",
        left: "0",
        top: "0",
        width: "1080px",
        height: `${height}px`,
        overflow: "hidden",
        pointerEvents: "none",
        zIndex: "0"
      });
      const exportStage = stage.cloneNode(true);
      Object.assign(exportStage.style, {
        position: "relative",
        inset: "auto",
        width: "1080px",
        height: `${height}px`,
        isolation: "auto",
        transform: "none",
        transformOrigin: "top left"
      });
      const exportBackground = exportStage.querySelector(".business-art-background");
      const capturedBackground = exportBackground?.style.backgroundImage || "";
      Object.assign(exportStage.style, {
        backgroundColor: "#071120",
        backgroundImage: capturedBackground
          ? `linear-gradient(rgba(2, 7, 18, .91), rgba(4, 12, 28, .95)), ${capturedBackground}`
          : "linear-gradient(180deg, #071120, #040c1c)",
        backgroundPosition: "center",
        backgroundSize: "cover"
      });
      exportBackground?.remove();
      exportStage.querySelector(".business-art-shade")?.remove();
      const exportCard = exportStage.querySelector(".business-art-card");
      if (exportCard) {
        exportCard.style.zIndex = "1";
        exportCard.style.overflow = "visible";
        exportCard.style.background = "#fff";
        exportCard.style.border = "none";
        exportCard.style.boxShadow = "none";
      }
      const exportDisclaimer = exportStage.querySelector(".business-art-disclaimer");
      if (exportDisclaimer) exportDisclaimer.style.zIndex = "1";
      exportHost.appendChild(exportStage);
      document.body.appendChild(exportHost);
      await aguardarImagensArteComercial(exportStage);

      const canvas = await html2canvas(exportStage, {
        width: 1080,
        height,
        scale: 1,
        useCORS: true,
        allowTaint: false,
        backgroundColor: null,
        logging: false,
        scrollX: 0,
        scrollY: 0,
        windowWidth: 1080,
        windowHeight: height
      });
      const link = document.createElement("a");
      const safeName = normalizarArteComercial(dados.nome) || slugId || "estabelecimento";
      link.download = `ola-carlopolis-${safeName}-${formato}.png`;
      link.href = canvas.toDataURL("image/png", 1);
      link.click();
      mostrarToast("Imagem pronta para compartilhar!");
    } catch (error) {
      console.error("Erro ao exportar a arte do estabelecimento.", error);
      mostrarToast("Nao foi possivel gerar a imagem. Tente novamente.");
    } finally {
      exportHost?.remove();
      button.disabled = false;
      button.innerHTML = original;
      resize();
    }
  });

  await render();
}

function chaveFirebaseMetrica(valor, fallback = "sem-identificacao") {
  const chave = String(valor || "").trim()
    .replace(/[.#$/[\]]/g, "-")
    .replace(/\s+/g, " ")
    .slice(0, 180);
  return chave || fallback;
}

function salvarOrigemCliqueLocal(info = {}) {
  try {
    const dados = {
      cidade: info.city || info.cidade || "",
      estado: info.region || info.estado || "",
      pais: info.country || info.pais || "",
      timezone: info.timezone || "",
      origem: info.origem || "",
      canal: info.canal || "",
      dispositivo: /Mobi|Android/i.test(navigator.userAgent) ? "mobile" : "desktop",
      atualizadoEm: Date.now()
    };
    sessionStorage.setItem("ola_carlopolis_origem_clique", JSON.stringify(dados));
    localStorage.setItem("ola_carlopolis_origem_clique", JSON.stringify(dados));
  } catch (error) {
    console.warn("Nao foi possivel salvar origem local do clique.", error);
  }
}

function origemParametroAtual() {
  try {
    const fontes = [
      window.location.search || "",
      window.location.hash.includes("?") ? `?${window.location.hash.split("?").slice(1).join("?")}` : ""
    ].filter(Boolean);
    for (const fonte of fontes) {
      const params = new URLSearchParams(fonte);
      const origemDireta = params.get("o") || params.get("origem") || params.get("qr") || params.get("qrcode");
      if (origemDireta) return origemDireta;
      const utmSource = params.get("utm_source");
      const utmCampaign = params.get("utm_campaign");
      if (utmSource || utmCampaign) return [utmSource, utmCampaign].filter(Boolean).join(" / ");
    }
  } catch (error) {}
  return "";
}

function origemAcessoAtual() {
  try {
    const origemUrl = origemParametroAtual();
    if (origemUrl) return origemUrl;
    if (document.referrer.includes("instagram.com")) return "instagram";
    if (window.matchMedia?.("(display-mode: standalone)").matches || window.navigator.standalone === true) return "app";
  } catch (error) {}
  return "site";
}

function canalAcessoAtual() {
  try {
    const isStandalone =
      window.matchMedia?.("(display-mode: standalone)").matches ||
      window.matchMedia?.("(display-mode: fullscreen)").matches ||
      window.matchMedia?.("(display-mode: minimal-ui)").matches ||
      window.navigator.standalone === true;
    return isStandalone ? "App (PWA)" : "Site (Navegador)";
  } catch (error) {
    return "Site (Navegador)";
  }
}

function origemCliqueAtual(extra = {}) {
  let dados = {};
  try {
    dados = JSON.parse(sessionStorage.getItem("ola_carlopolis_origem_clique") || localStorage.getItem("ola_carlopolis_origem_clique") || "{}") || {};
  } catch (error) {
    dados = {};
  }
  return {
    cidade: extra.cidadeOrigem || extra.cidadeAcesso || extra.clickCidade || dados.cidade || extra.cidade || extra.city || "",
    estado: extra.estadoOrigem || extra.estadoAcesso || extra.clickEstado || dados.estado || extra.estado || extra.region || "",
    pais: extra.paisOrigem || extra.paisAcesso || extra.clickPais || dados.pais || extra.pais || extra.country || "",
    timezone: extra.timezone || dados.timezone || Intl.DateTimeFormat().resolvedOptions().timeZone || "",
    origem: extra.origem || dados.origem || origemAcessoAtual(),
    canal: extra.canal || dados.canal || canalAcessoAtual(),
    dispositivo: extra.dispositivo || dados.dispositivo || (/Mobi|Android/i.test(navigator.userAgent) ? "mobile" : "desktop")
  };
}

function variantesChaveMetricaCliente(valor) {
  const bruto = String(valor || "").trim();
  if (!bruto) return [];
  const slug = bruto
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  const compacta = slug.replace(/-/g, "");
  const variantes = new Set([bruto, slug, compacta]);
  const partes = slug.split("-").filter(Boolean);
  if (partes.length > 1) {
    variantes.add(partes.slice(0, 2).join("-"));
    variantes.add(partes.slice(0, 2).join(""));
    variantes.add(partes.slice(0, 3).join("-"));
    variantes.add(partes.slice(0, 3).join(""));
    variantes.add(partes.slice(1).join("-"));
    variantes.add(partes.slice(1).join(""));
    variantes.add(partes.slice(-2).join("-"));
    variantes.add(partes.slice(-2).join(""));
    variantes.add(partes.slice(-3).join("-"));
    variantes.add(partes.slice(-3).join(""));
  }
  return [...variantes].filter(Boolean);
}

function registrarMetricaCliente(idEstabelecimento, grupo, tipo, detalhes = {}) {
  const explicitClientId = String(detalhes.clienteId || "").trim();
  const explicitClientKey = /^[a-z0-9-]+$/.test(explicitClientId) ? explicitClientId : "";
  const metricCandidates = [
    explicitClientKey,
    detalhes.clienteId,
    detalhes.estabelecimentoId,
    detalhes.clienteNome,
    detalhes.vendedor,
    detalhes.loja,
    detalhes.corretor,
    idEstabelecimento
  ].filter(Boolean);
  const clienteKey = explicitClientKey || metricCandidates.map(resolverChaveMetricaCliente).find(Boolean);
  if (!clienteKey) return Promise.resolve();

  const hoje = getHojeBR();
  const db = firebase.database();
  const contadorPath = tipo
    ? `metricasClientes/${clienteKey}/${hoje}/${grupo}/${tipo}`
    : `metricasClientes/${clienteKey}/${hoje}/${grupo}`;
  const contador = db.ref(contadorPath).transaction((atual) => (atual || 0) + 1);
  const origemClique = origemCliqueAtual(detalhes);
  const log = db.ref(`metricasClientes/${clienteKey}/${hoje}/detalhes`).push().set({
    grupo,
    tipo: tipo || grupo,
    ...detalhes,
    ...origemClique,
    horario: new Date().toLocaleTimeString("pt-BR", { timeZone: "America/Sao_Paulo" }),
    dataHoraISO: new Date().toISOString(),
    ts: firebase.database.ServerValue.TIMESTAMP,
    pagina: window.location.href
  });

  return Promise.allSettled([contador, log]);
}

function registrarOrigemPaginaCliente(idEstabelecimento, detalhes = {}) {
  const explicitClientId = String(detalhes.clienteId || "").trim();
  const explicitClientKey = /^[a-z0-9-]+$/.test(explicitClientId) ? explicitClientId : "";
  const metricCandidates = [
    explicitClientKey,
    detalhes.clienteId,
    detalhes.estabelecimentoId,
    detalhes.clienteNome,
    detalhes.estabelecimento,
    idEstabelecimento
  ].filter(Boolean);
  const clienteKey = explicitClientKey || metricCandidates.map(resolverChaveMetricaCliente).find(Boolean);
  if (!clienteKey) return Promise.resolve();

  const hoje = getHojeBR();
  const origemInfo = origemCliqueAtual();
  const origemBruta = String(origemInfo.origem || "site").trim() || "site";
  const origemKey = chaveFirebaseMetrica(origemBruta, "acesso-direto");
  const dedupeKey = `${clienteKey}|${hoje}|${origemKey}|${window.location.pathname}${window.location.search}${window.location.hash}`;
  window.__origemPaginaClienteRegistrada = window.__origemPaginaClienteRegistrada || new Set();
  if (window.__origemPaginaClienteRegistrada.has(dedupeKey)) return Promise.resolve();
  window.__origemPaginaClienteRegistrada.add(dedupeKey);

  const agora = new Date();
  const db = firebase.database();
  const contador = db.ref(`metricasClientes/${clienteKey}/${hoje}/origensPagina/${origemKey}`).transaction((atual) => (atual || 0) + 1);
  const log = db.ref(`metricasClientes/${clienteKey}/${hoje}/detalhesOrigemPagina`).push().set({
    grupo: "origensPagina",
    tipo: "origem_pagina",
    origem: origemBruta,
    ...origemInfo,
    ...detalhes,
    horario: agora.toLocaleTimeString("pt-BR", { timeZone: "America/Sao_Paulo" }),
    dataHoraISO: agora.toISOString(),
    ts: firebase.database.ServerValue.TIMESTAMP,
    pagina: window.location.href
  });

  return Promise.allSettled([contador, log]);
}

function erroPermissaoFirebase(erro) {
  const texto = String(erro?.code || erro?.message || erro || "").toLowerCase();
  return texto.includes("permission_denied") || texto.includes("permission denied");
}

// Função para registrar clique no Firebase (contador + detalhado)
function registrarCliqueBotao(tipo, idEstabelecimento, area = "botoes", detalhes = {}) {
  const hoje = getHojeBR();
  const db = firebase.database();
  const chaveEstabelecimento = chaveFirebaseMetrica(idEstabelecimento);
  const chaveTipo = chaveFirebaseMetrica(tipo, "clique");

  const agora = new Date();
  const origemClique = origemCliqueAtual(detalhes);
  const payload = {
    area,
    tipo,
    ...detalhes,
    ...origemClique,
    horario: agora.toLocaleTimeString("pt-BR"),
    dataHoraISO: agora.toISOString(),
    ts: firebase.database.ServerValue.TIMESTAMP,
    pagina: window.location.href
  };
  const metricaCliente = registrarMetricaCliente(idEstabelecimento, "botoes", tipo, {
    area,
    ...detalhes
  });

  const gravacoes = [metricaCliente];
  try {
    gravacoes.push(db.ref(`cliquesPorBotao/${hoje}/${chaveEstabelecimento}/${chaveTipo}`).transaction((atual) => (atual || 0) + 1));
    gravacoes.push(db.ref(`cliquesPorBotaoDetalhado/${hoje}/${chaveEstabelecimento}`).push().set(payload));
  } catch (erro) {
    if (!erroPermissaoFirebase(erro)) {
      console.warn("[CliqueBotao] Erro ao preparar contador:", erro);
    }
  }

  return Promise.allSettled(gravacoes).then((resultados) => {
    const ok = resultados.some((resultado) => resultado.status === "fulfilled");
    resultados
      .filter((resultado) => resultado.status === "rejected" && !erroPermissaoFirebase(resultado.reason))
      .forEach((resultado) => console.warn("[CliqueBotao] Erro ao registrar clique:", resultado.reason));
    return { ok };
  });
}
window.registrarCliqueBotao = registrarCliqueBotao;



// === VALIDADE: helpers (expira só DEPOIS da data final) ===
function isDepoisDeHojeStr(dataISO) {
  const hoje = getHojeBR();              // 'YYYY-MM-DD' em UTC-3
  return hoje > String(dataISO || "");   // só considera expirado no DIA SEGUINTE
}

function promoExpirada(p) {
  return Boolean(p?.validadeFim) && isDepoisDeHojeStr(p.validadeFim);
}

function normalizarDiasSemanaPromocao(valor) {
  const valores = Array.isArray(valor) ? valor : (valor === undefined || valor === null || valor === "" ? [] : [valor]);
  return [...new Set(valores
    .map((item) => Number(item))
    .filter((item) => Number.isInteger(item) && item >= 0 && item <= 6))];
}

function diaSemanaAtualCarlopolis() {
  return new Date(new Date().toLocaleString("en-US", { timeZone: "America/Sao_Paulo" })).getDay();
}

function promoDisponivelHoje(p) {
  const dias = normalizarDiasSemanaPromocao(p?.diasSemana || p?.dias || p?.recorrenciaDias || p?.diaSemana);
  return !dias.length || dias.includes(diaSemanaAtualCarlopolis());
}

function textoDiasPromocao(p) {
  const dias = normalizarDiasSemanaPromocao(p?.diasSemana || p?.dias || p?.recorrenciaDias || p?.diaSemana);
  if (!dias.length) return "";
  const labels = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sab"];
  return `Disponivel: ${dias.map((dia) => labels[dia]).filter(Boolean).join(", ")}`;
}

// === Identidade local do jogador (permite atualizar recorde sem repedir nome) ===
function getOrCreatePlayerId() {
  let id = localStorage.getItem("capivarinha_player_id");
  if (!id) {
    id = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 9)}`;
    localStorage.setItem("capivarinha_player_id", id);
  }
  return id;
}

// === Capivarinha: helpers para ranking ==
function getPlayerName() {
  // guarda localmente para não perguntar toda hora
  let nm = localStorage.getItem("capivarinha_player_name") || "";
  if (!nm) {
    nm = prompt("Qual seu nome para o Ranking? (exibido publicamente)") || "";
    nm = nm.trim().slice(0, 30);
    if (nm) localStorage.setItem("capivarinha_player_name", nm);
  }
  return nm;
}

function setPlayerName(newName) {
  const nm = String(newName || "").trim().slice(0, 30);
  if (!nm) return false;
  localStorage.setItem("capivarinha_player_name", nm);
  return true;
}

function capivarinhaDateKey(date = new Date()) {
  const parts = new Intl.DateTimeFormat("pt-BR", {
    timeZone: "America/Sao_Paulo",
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(date);
  const values = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  return `${values.year}-${values.month}-${values.day}`;
}

function capivarinhaFormatDateBR(value) {
  if (!value) return "Data não informada";
  if (/^\d{4}-\d{2}-\d{2}$/.test(String(value))) {
    const [year, month, day] = String(value).split("-");
    return `${day}/${month}/${year}`;
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "Data não informada";
  return date.toLocaleDateString("pt-BR", { timeZone: "America/Sao_Paulo" });
}

function capivarinhaRecordDateKey(item = {}) {
  if (item.bestDate) return String(item.bestDate);
  const timestamp = Number(item.bestAt || item.updatedAt || item.ts || 0);
  if (timestamp > 0) return capivarinhaDateKey(new Date(timestamp));
  if (item.bestDateTime) return capivarinhaDateKey(new Date(item.bestDateTime));
  return "";
}

function escapeGameHtml(value) {
  return String(value || "").replace(/[&<>"']/g, (ch) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#39;"
  }[ch]));
}

function salvarScoreCapivarinha(score) {
  try {
    if (!window.firebase || !firebase.database) {
      console.warn("Firebase não disponível");
      return;
    }
    if (!(score > 0)) return;

    const uid = getOrCreatePlayerId();
    const name = getPlayerName();
    if (!name) return;
    const agora = new Date();
    const agoraMs = agora.getTime();
    const dataRecorde = capivarinhaDateKey(agora);
    const dataHoraRecorde = agora.toISOString();

    const db = firebase.database();
    const userRef = db.ref(`jogos/capivarinha/users/${uid}`);

    // Atualiza histórico opcional (mantém cada partida, se você quiser estatística)
    db.ref("jogos/capivarinha/scores").push({
      uid, name, score: Number(score),
      date: dataRecorde,
      dateTime: dataHoraRecorde,
      ts: agoraMs
    }).catch(() => { });

    // Transaction para manter o MELHOR score (best) do usuário
    userRef.transaction((curr) => {
      const best = curr?.best ?? 0;
      if (!curr) {
        // primeira vez
        return {
          name,
          best: Number(score),
          bestAt: agoraMs,
          bestDate: dataRecorde,
          bestDateTime: dataHoraRecorde,
          updatedAt: agoraMs
        };
      }
      // atualiza nome (pode ter sido trocado) e recorde se for maior
      const novoRecorde = Number(score) > Number(best);
      return {
        ...curr,
        name,
        best: Math.max(Number(best), Number(score)),
        bestAt: novoRecorde ? agoraMs : (curr.bestAt || curr.updatedAt || agoraMs),
        bestDate: novoRecorde ? dataRecorde : (curr.bestDate || capivarinhaRecordDateKey(curr)),
        bestDateTime: novoRecorde ? dataHoraRecorde : (curr.bestDateTime || ""),
        updatedAt: agoraMs
      };
    }).then(() => {
      console.log("Recorde verificado/atualizado:", name, score);
    }).catch(err => console.error("Falha ao salvar/atualizar recorde:", err));
  } catch (e) {
    console.error("Erro salvarScoreCapivarinha:", e);
  }
}


function mostrarRankingCapivarinha() {
  if (location.hash !== "#ranking-capivarinha") location.hash = "#ranking-capivarinha";

  const area = document.querySelector(".content_area");
  area.innerHTML = `
    <div class="page-header">
      <h2>🏆 Ranking Capivarinha</h2>
      <i class="fa-solid fa-share-nodes share-btn"
         onclick="compartilharPagina('#ranking-capivarinha','Ranking Capivarinha','Veja o ranking do jogo Capivarinha!')"></i>
    </div>

    <div class="rank-wrap" style="padding:8px 12px">
      <div class="rank-title">
  🏅 Top Records <span><br>(melhor pontuação por jogador)</span>
</div>
      <div class="rank-filter-card">
        <label>Data de
          <input id="rankDataInicio" type="date">
        </label>
        <label>Data até
          <input id="rankDataFim" type="date">
        </label>
        <label>Ordenar por
          <select id="rankOrdenacao">
            <option value="score">Maior pontuação</option>
            <option value="data-recente">Data mais recente</option>
            <option value="data-antiga">Data mais antiga</option>
          </select>
        </label>
        <button class="btn-rank" id="rankLimparDatas" type="button">Limpar datas</button>
      </div>
      <ul id="rankList" class="rank-list"></ul>

      <div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap">
        <button class="btn-rank" onclick="location.hash='canos'; mostrarCanos()">⬅️ Voltar ao Capivarinha</button>
        <!--<button class="btn-rank" id="btnTrocarNome">✏️ Trocar nome</button>-->
        <button class="btn-rank" id="btnMeuRecorde">👤 Meu recorde</button>
      </div>
    </div>
  `;

  const ul = document.getElementById("rankList");
  const inputInicio = document.getElementById("rankDataInicio");
  const inputFim = document.getElementById("rankDataFim");
  const inputOrdenacao = document.getElementById("rankOrdenacao");
  const btnLimparDatas = document.getElementById("rankLimparDatas");
  const filtrosRanking = { inicio: "", fim: "", ordenacao: "score" };

  // segurança: sem Firebase, mostra aviso e sai
  if (!window.firebase || !firebase.database) {
    ul.innerHTML = `<li class="rank-empty">⚠️ Firebase indisponível.</li>`;
    return;
  }

  // pega/gera meu id local (já existe no seu arquivo)
  const myUid = getOrCreatePlayerId();

  // consulta os usuários ordenando por "best" (melhor recorde) — pega até 50
  const ref = firebase.database()
    .ref("jogos/capivarinha/users")
    .orderByChild("best")
    .limitToLast(50);

  const renderRanking = (snap) => {
    const arr = [];
    snap.forEach(ch => {
      const v = ch.val();
      if (v && typeof v.best === "number") {
        // guardo a chave do nó para identificar quem sou eu
        arr.push({ ...v, _id: ch.key });
      }
    });

    // ordena do maior para o menor
    const filtrados = arr.filter((item) => {
      const data = capivarinhaRecordDateKey(item);
      const inicioOk = !filtrosRanking.inicio || (data && data >= filtrosRanking.inicio);
      const fimOk = !filtrosRanking.fim || (data && data <= filtrosRanking.fim);
      return inicioOk && fimOk;
    }).sort((a, b) => {
      const dataA = capivarinhaRecordDateKey(a);
      const dataB = capivarinhaRecordDateKey(b);
      if (filtrosRanking.ordenacao === "data-recente") return String(dataB).localeCompare(String(dataA)) || b.best - a.best;
      if (filtrosRanking.ordenacao === "data-antiga") return String(dataA).localeCompare(String(dataB)) || b.best - a.best;
      return b.best - a.best;
    });

    if (!filtrados.length) {
      ul.innerHTML = `<li class="rank-empty">${arr.length ? "Nenhum recorde encontrado para o período selecionado." : "Ninguém no ranking ainda. Jogue e salve seu score! 🎮"}</li>`;
      return;
    }

    const top = filtrados[0]?.best || 1;

    ul.innerHTML = filtrados.map((it, i) => {
      const pos = i + 1;
      const medalClass = pos === 1 ? "medal-1" : pos === 2 ? "medal-2" : pos === 3 ? "medal-3" : "";
      const fillPct = Math.max(6, Math.round((Number(it.best || 0) / top) * 100));
      const isMe = it._id === myUid;
      const dataRecorde = capivarinhaRecordDateKey(it);

      return `
    <li class="rank-item rank-item--compact ${isMe ? "me" : ""}">
      <div class="rank-pos ${medalClass}">${pos}</div>
      <div class="rank-main">
        <div class="rank-row">
          <div class="rank-name" title="${(it.name || "Jogador").toString().slice(0, 60)}">
            ${(it.name || "Jogador").toString().slice(0, 30)}
          </div>
          <div class="score-number">${Number(it.best || 0)}</div>
        </div>
        <div class="rank-date"><i class="fa-regular fa-calendar"></i> ${capivarinhaFormatDateBR(dataRecorde)}</div>
        <div class="score-bar">
          <div class="score-fill" style="width:${fillPct}%"></div>
        </div>
      </div>
    </li>
  `;
    }).join("");



    // rolar até minha posição (se eu estiver na lista)
    const myItem = ul.querySelector(".rank-item.me");
    if (myItem) myItem.scrollIntoView({ behavior: "smooth", block: "center" });
  };

  let rankingSnapshot = null;
  ref.on("value", (snap) => {
    rankingSnapshot = snap;
    renderRanking(snap);
  });

  const aplicarFiltroDataRanking = () => {
    filtrosRanking.inicio = inputInicio?.value || "";
    filtrosRanking.fim = inputFim?.value || "";
    filtrosRanking.ordenacao = inputOrdenacao?.value || "score";
    if (rankingSnapshot) renderRanking(rankingSnapshot);
  };
  inputInicio?.addEventListener("change", aplicarFiltroDataRanking);
  inputFim?.addEventListener("change", aplicarFiltroDataRanking);
  inputOrdenacao?.addEventListener("change", aplicarFiltroDataRanking);
  btnLimparDatas?.addEventListener("click", () => {
    if (inputInicio) inputInicio.value = "";
    if (inputFim) inputFim.value = "";
    aplicarFiltroDataRanking();
  });

  // Botão "Trocar nome"
  const btnTrocar = document.getElementById("btnTrocarNome");
  if (btnTrocar) btnTrocar.addEventListener("click", () => {
    const novo = prompt("Novo nome para o Ranking:");
    if (setPlayerName(novo)) {
      const uid = getOrCreatePlayerId();
      firebase.database().ref(`jogos/capivarinha/users/${uid}/name`)
        .set(localStorage.getItem("capivarinha_player_name"))
        .then(() => alert("Nome atualizado!"));
    }
  });

  // Botão "Meu recorde" — rola até mim
  // Botão "Meu recorde" — mostra o valor e rola até mim
  const btnMeuRecorde = document.getElementById("btnMeuRecorde");
  if (btnMeuRecorde) btnMeuRecorde.addEventListener("click", async () => {
    try {
      const uid = getOrCreatePlayerId();
      const snap = await firebase.database()
        .ref(`jogos/capivarinha/users/${uid}`)
        .once("value");

      const data = snap.val();
      if (data && typeof data.best === "number") {
        alert(`Seu recorde: ${data.best}`);

        // tenta rolar até sua linha, se ela estiver no Top exibido
        const myItem = document.querySelector(".rank-item.me");
        if (myItem) myItem.scrollIntoView({ behavior: "smooth", block: "center" });
      } else {
        alert("Você ainda não tem recorde salvo. Jogue uma partida para entrar no ranking!");
      }
    } catch (e) {
      console.error(e);
      alert("Não consegui carregar seu recorde agora. Tente novamente.");
    }
  });

}

