function represaRegistroId(date, horario = '') {
  const dateKey = date.toISOString().slice(0, 10);
  const timeKey = String(horario || '').trim().replace(/\D/g, '').slice(0, 4);
  return `${dateKey}-${timeKey ? `${timeKey.slice(0, 2)}-${timeKey.slice(2, 4)}` : 'diario'}`;
}

function normalizarRegistroRepresa(data = {}) {
  const atualizadoEm = data.atualizadoEm || data.ultimaAtualizacao || data.data || Date.now();
  const parsedDate = new Date(atualizadoEm);
  const date = Number.isNaN(parsedDate.getTime()) ? new Date() : parsedDate;
  const cota = valorNumeroRepresa(data.cotaAtual ?? data.cota ?? data.nivel ?? data.nivel_m);
  const volume = valorNumeroRepresa(data.volumeUtil ?? data.volume ?? data.volumeUtilPct ?? data.volume_util_pct);
  const defluencia = valorNumeroRepresa(data.vazaoDefluente ?? data.defluente ?? data.defluencia_m3s);
  const afluencia = valorNumeroRepresa(data.vazaoAfluente ?? data.afluente);
  if (!Number.isFinite(cota) && !Number.isFinite(volume)) return null;
  const horario = data.horarioReferencia || data.horario || '';
  return {
    id: represaRegistroId(date, horario),
    dataISO: date.toISOString(),
    dataLabel: date.toLocaleDateString('pt-BR'),
    horario: horario || date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
    cota,
    volume,
    defluencia,
    afluencia,
    fonte: data.fonte || 'CTG Brasil'
  };
}

function represaFirebaseDisponivel() {
  return !!(window.firebase && firebase.database);
}

function represaHistoricoRef() {
  if (!represaFirebaseDisponivel()) return null;
  return firebase.database().ref('represas/chavantes/historico');
}

async function lerHistoricoRepresaRemoto() {
  const ref = represaHistoricoRef();
  if (ref) {
    const snap = await ref.once('value');
    return snap.val() || {};
  }

  const response = await fetch(`${REPRESA_HISTORICO_FIREBASE_REST}.json`, { cache: 'no-store' });
  if (!response.ok) throw new Error(`Firebase REST retornou ${response.status}`);
  return await response.json() || {};
}

async function salvarRegistroRepresaRemoto(registro) {
  const ref = represaHistoricoRef();
  if (ref) {
    await ref.child(registro.id).set({
      ...registro,
      salvoEm: firebase.database.ServerValue.TIMESTAMP
    });
    return;
  }

  const response = await fetch(`${REPRESA_HISTORICO_FIREBASE_REST}/${encodeURIComponent(registro.id)}.json`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      ...registro,
      salvoEm: Date.now()
    })
  });
  if (!response.ok) throw new Error(`Firebase REST retornou ${response.status}`);
}

function normalizarListaHistoricoRepresa(list = []) {
  const mapa = new Map(REPRESA_HISTORICO_INICIAL.map((item) => [item.id, { ...item }]));
  if (Array.isArray(list)) {
    list.filter(Boolean).forEach((item) => {
      if (item?.id) mapa.set(item.id, item);
    });
  } else if (list && typeof list === 'object') {
    Object.entries(list).forEach(([id, item]) => {
      if (item && typeof item === 'object') mapa.set(item.id || id, { id: item.id || id, ...item });
    });
  }
  return Array.from(mapa.values()).sort((a, b) => new Date(a.dataISO) - new Date(b.dataISO));
}

function lerHistoricoRepresaLocal() {
  const base = REPRESA_HISTORICO_INICIAL.map((item) => ({ ...item }));
  try {
    const raw = localStorage.getItem(REPRESA_HISTORICO_KEY);
    const list = raw ? JSON.parse(raw) : [];
    return normalizarListaHistoricoRepresa([...base, ...(Array.isArray(list) ? list : [])]);
  } catch (_) {
    return base;
  }
}

function salvarHistoricoRepresaLocal(historico = []) {
  try {
    localStorage.setItem(REPRESA_HISTORICO_KEY, JSON.stringify(historico.slice(-730)));
  } catch (_) {
    // Historico local e opcional; se o navegador bloquear, a tela principal continua funcionando.
  }
}

async function lerHistoricoRepresa() {
  const local = lerHistoricoRepresaLocal();
  try {
    const remoto = await lerHistoricoRepresaRemoto();
    const historico = normalizarListaHistoricoRepresa([...local, ...Object.values(remoto)]);
    salvarHistoricoRepresaLocal(historico);
    return historico;
  } catch (error) {
    console.warn('Historico da represa indisponivel no Firebase; usando copia local.', error);
    return local;
  }
}

async function salvarHistoricoRepresa(data = {}) {
  const registro = normalizarRegistroRepresa(data);
  if (!registro) return null;
  const historico = (await lerHistoricoRepresa()).filter((item) => item.id !== registro.id);
  historico.push(registro);
  historico.sort((a, b) => new Date(a.dataISO) - new Date(b.dataISO));
  salvarHistoricoRepresaLocal(historico);

  try {
    await salvarRegistroRepresaRemoto(registro);
  } catch (error) {
    console.warn('Nao foi possivel salvar historico da represa no Firebase.', error);
  }
  return registro;
}

async function filtrarHistoricoRepresa(periodo = '30') {
  const historico = await lerHistoricoRepresa();
  if (periodo === 'todos') return historico;
  const dias = Number(periodo || 30);
  const limite = new Date();
  limite.setDate(limite.getDate() - Math.max(dias - 1, 0));
  limite.setHours(0, 0, 0, 0);
  return historico.filter((item) => new Date(item.dataISO) >= limite);
}

async function renderHistoricoRepresa(periodo = '30', registroAtual = null) {
  const box = document.getElementById('represaHistoricoBox');
  if (!box) return;
  const mapa = new Map((await filtrarHistoricoRepresa(periodo)).map((item) => [item.id, item]));
  if (registroAtual?.id) mapa.set(registroAtual.id, registroAtual);
  const dedupePorHorario = new Map();
  Array.from(mapa.values())
    .sort((a, b) => new Date(a.dataISO) - new Date(b.dataISO))
    .forEach((item) => {
      const dia = item.dataLabel || new Date(item.dataISO).toLocaleDateString('pt-BR');
      const hora = String(item.horario || '').trim() || new Date(item.dataISO).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
      dedupePorHorario.set(`${dia}-${hora}`, { ...item, dataLabel: dia, horario: hora });
    });
  const dados = Array.from(dedupePorHorario.values()).sort((a, b) => new Date(a.dataISO) - new Date(b.dataISO));
  if (!dados.length) {
    box.innerHTML = `
      <div class="represa-history-empty">
        Ainda nao ha historico suficiente. O dado atual sera salvo e os proximos acessos vao preencher este grafico.
      </div>
    `;
    return;
  }

  const cotaValores = dados.map((item) => item.cota).filter(Number.isFinite);
  const volumeValores = dados.map((item) => item.volume).filter(Number.isFinite);
  const cotaMin = Math.min(...cotaValores);
  const cotaMax = Math.max(...cotaValores);
  const span = cotaMax - cotaMin || 1;
  const pontosBase = dados.map((item, index) => {
    const x = dados.length === 1 ? 50 : (index / (dados.length - 1)) * 100;
    const y = Number.isFinite(item.cota) ? 88 - (((item.cota - cotaMin) / span) * 66) : 88;
    return `${x.toFixed(2)},${y.toFixed(2)}`;
  });
  const pontos = dados.length === 1 ? `8,${pontosBase[0].split(',')[1]} 92,${pontosBase[0].split(',')[1]}` : pontosBase.join(' ');
  const volumeMedio = volumeValores.length ? volumeValores.reduce((sum, value) => sum + value, 0) / volumeValores.length : null;
  const cotaAtual = cotaValores.length ? cotaValores[cotaValores.length - 1] : null;
  const cotaMeio = (cotaMax + cotaMin) / 2;

  box.innerHTML = `
    <div class="represa-history-summary">
      <div><span>Registros</span><strong>${dados.length}</strong></div>
      <div><span>Cota atual</span><strong>${Number.isFinite(cotaAtual) ? cotaAtual.toFixed(2) + ' m' : '-'}</strong></div>
      <div><span>Volume medio</span><strong>${Number.isFinite(volumeMedio) ? volumeMedio.toFixed(2) + '%' : '-'}</strong></div>
    </div>
    <div class="represa-history-chart-shell">
      <div class="represa-history-axis" aria-hidden="true">
        <span>${cotaMax.toFixed(2)} m</span>
        <span>${cotaMeio.toFixed(2)} m</span>
        <span>${cotaMin.toFixed(2)} m</span>
      </div>
      <div class="represa-history-chart" aria-label="Grafico do nivel da represa">
        <svg viewBox="0 0 100 100" preserveAspectRatio="none">
          <line x1="0" y1="22" x2="100" y2="22"></line>
          <line x1="0" y1="55" x2="100" y2="55"></line>
          <line x1="0" y1="88" x2="100" y2="88"></line>
          <polyline points="${pontos}"></polyline>
        </svg>
      </div>
    </div>
    <div class="represa-history-table-wrap">
      <table class="represa-history-table">
        <thead>
          <tr>
            <th>Data</th>
            <th>Nivel</th>
            <th>Volume</th>
            <th>Defluencia</th>
          </tr>
        </thead>
        <tbody>
          ${dados.slice().reverse().map((item) => `
            <tr>
              <td>${item.dataLabel}${item.horario ? `<small>${item.horario}</small>` : ''}</td>
              <td>${Number.isFinite(item.cota) ? item.cota.toFixed(2) + ' m' : '-'}</td>
              <td>${Number.isFinite(item.volume) ? item.volume.toFixed(2) + '%' : '-'}</td>
              <td>${Number.isFinite(item.defluencia) ? item.defluencia.toFixed(2) + ' m3/s' : '-'}</td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
}

async function carregarDadosRepresa() {
  // TODO: substitua por seu fetch real (ONS/Vercel/etc.)
  // Estrutura sugerida:
  // { ultimaAtualizacaoISO, sobre, cotaAtual_m, cotaRef_m, volumeAtual_pct, volumeRef_pct }
  return {
    ultimaAtualizacaoISO: new Date().toISOString(),
    sobre: "Reservatório de Chavantes – dados diários do ONS.",
    cotaAtual_m: window.nivelChavantes?.cota ?? 474.32,    // se já existir algo global, usa
    cotaRef_m: 474.00,
    volumeAtual_pct: window.nivelChavantes?.volume ?? 58.7,
    volumeRef_pct: 60.0
  };
}

function formatarDataBR(iso) {
  try {
    const d = new Date(iso);
    return d.toLocaleString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" });
  } catch (_) { return "—"; }
}

async function mostrarRepresa() {
  location.hash = "#represa-chavantes"; // âncora amigável

  const area = document.querySelector(".content_area");
  if (!area) return;

  // carrega dados (troque pelo seu fetch real)
  const dados = await carregarDadosRepresa();

  const statusCota = classificarComparacao(dados.cotaAtual_m, dados.cotaRef_m);
  const statusVol = classificarComparacao(dados.volumeAtual_pct, dados.volumeRef_pct);

  // --- Comparação direta: Nível de Referência x Cota Atual ---
  const nivelRef = Number(dados.cotaRef_m ?? 0);
  const cotaAtual = Number(dados.cotaAtual_m ?? 0);
  const statusComparativo = classificarComparacao(cotaAtual, nivelRef);
  const badgeComp = statusComparativo === "high" ? "high" : (statusComparativo === "low" ? "low" : "equal");
  const cardClasseComp = statusComparativo === "high" ? "status-high" : (statusComparativo === "low" ? "status-low" : "");
  const diffAbs = (Number.isFinite(cotaAtual) && Number.isFinite(nivelRef)) ? (cotaAtual - nivelRef) : 0;
  const diffPct = (Number.isFinite(nivelRef) && nivelRef !== 0) ? (diffAbs / nivelRef) * 100 : 0;



  const badgeCota = statusCota === "high" ? "high" : (statusCota === "low" ? "low" : "equal");
  const badgeVol = statusVol === "high" ? "high" : (statusVol === "low" ? "low" : "equal");

  const cardClasseCota = statusCota === "high" ? "status-high" : (statusCota === "low" ? "status-low" : "");
  const cardClasseVol = statusVol === "high" ? "status-high" : (statusVol === "low" ? "status-low" : "");

  const ultima = formatarDataBR(dados.ultimaAtualizacaoISO);

  area.innerHTML = `
    <div class="represa-wrap">
      <div class="represa-header">
        <h2>💧 Represa de Chavantes</h2>
        <div class="sub">Fonte: ONS • Atualização diária</div>
      </div>

      <div class="represa-grid">

        <!-- Card: Cota (nível) com comparação -->
        <div class="represa-card ${cardClasseCota}">
          <div class="card-meta">
            <div class="meta-row"><b>Última Atualização:</b> ${ultima}</div>
            <div class="meta-row"><b>Sobre a Represa:</b> ${dados.sobre}</div>
          </div>
          <div class="card-body">
            <div class="represa-label">Cota (nível)</div>
            <div class="represa-metric">
              <div class="val">${Number(dados.cotaAtual_m ?? 0).toFixed(2)}</div>
              <div class="unit">m</div>
            </div>
            <div>
              Ref.: <b>${Number(dados.cotaRef_m ?? 0).toFixed(2)} m</b>
              &nbsp;•&nbsp;
              <span class="represa-badge ${badgeCota}">
                ${statusCota === "high" ? "ALTO" : statusCota === "low" ? "BAIXO" : "IGUAL"}
              </span>
            </div>
          </div>
        </div>

                <!-- Card: Volume Útil (%) com comparação -->
        <div class="represa-card ${cardClasseVol}">
          <div class="card-meta">
            <div class="meta-row"><b>Última Atualização:</b> ${ultima}</div>
            <div class="meta-row"><b>Sobre a Represa:</b> ${dados.sobre}</div>
          </div>
          <div class="card-body">
            <div class="represa-label">Volume Útil</div>
            <div class="represa-metric">
              <div class="val">${Number(dados.volumeAtual_pct ?? 0).toFixed(1)}</div>
              <div class="unit">%</div>
            </div>
            <div>
              Ref.: <b>${Number(dados.volumeRef_pct ?? 0).toFixed(1)}%</b>
              &nbsp;•&nbsp;
              <span class="represa-badge ${badgeVol}">
                ${statusVol === "high" ? "ALTO" : statusVol === "low" ? "BAIXO" : "IGUAL"}
              </span>
            </div>
          </div>
        </div>

        <!-- Card: Comparação Nível de Referência × Cota Atual -->
        <div class="represa-card ${cardClasseComp}">
          <div class="card-meta">
            <div class="meta-row"><b>Última Atualização:</b> ${ultima}</div>
            <div class="meta-row"><b>Sobre a Represa:</b> ${dados.sobre}</div>
          </div>
          <div class="card-body">
            <div class="represa-label">Nível de Referência × Cota Atual</div>

            <div class="represa-compare">
              <div class="rep-item">
                <div class="rep-title">Referência</div>
                <div class="rep-value">${nivelRef.toFixed(2)} <span class="unit">m</span></div>
              </div>
              <div class="rep-item">
                <div class="rep-title">Cota Atual</div>
                <div class="rep-value">${cotaAtual.toFixed(2)} <span class="unit">m</span></div>
              </div>
            </div>

            <div class="represa-diff">
              <span class="rep-diff-number">${diffAbs >= 0 ? "+" : ""}${diffAbs.toFixed(2)} m</span>
              <span class="rep-diff-number">(${diffPct >= 0 ? "+" : ""}${diffPct.toFixed(2)}%)</span>
              <span class="represa-badge ${badgeComp}">
                ${statusComparativo === "high" ? "ALTO" : statusComparativo === "low" ? "BAIXO" : "IGUAL"}
              </span>
            </div>

            <div class="rep-note">Comparação direta entre o valor de referência configurado e a cota atual.</div>
          </div>
        </div>


        <!-- Exemplo de mais um card informativo (opcional) -->
        <div class="represa-card">
          <div class="card-meta">
            <div class="meta-row"><b>Última Atualização:</b> ${ultima}</div>
            <div class="meta-row"><b>Sobre a Represa:</b> ${dados.sobre}</div>
          </div>
          <div class="card-body">
            <div class="represa-label">Observações</div>
            <div style="font-size:13px;color:#333">
              • Valores sujeitos a revisão pelo ONS<br>
              • Comparação feita contra o valor de referência configurado
            </div>
          </div>
        </div>

      </div>
    </div>
  `;
}

