  // Função para identificar a origem do acesso
  function getOrigemAcesso() {
    const urlParams = new URLSearchParams(window.location.search);
    const origemUrl = urlParams.get('o'); // Detecta se tem ?o=instagram na URL

    // 1. Verifica se veio do Instagram
    if (origemUrl === 'instagram' || document.referrer.includes('instagram.com')) {
      return 'insta';
    }
    // 2. Verifica se veio do App (PWA)
    // Nota: Aqui usei a lógica da sua função detectarCanalAcesso()
    if (window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true) {
      return 'app';
    }
    // 3. Padrão: Site
    return 'site';
  }

  // Variavel global para controle do pulso
  let contadorAnterior = 0;

  function inicializarContadorOnline() {
    const contadorEl = document.getElementById("contadorOnline");
    const iconeEl = document.getElementById("iconeUsuarios");

    if (!contadorEl || !window.firebase?.database) return;
    if (location.pathname.toLowerCase().includes("/admin/")) return;

    const onlineUsersRef = firebase.database().ref("onlineUsers");
    const connectedRef = firebase.database().ref(".info/connected");
    const INACTIVE_LIMIT_MS = 20 * 60 * 1000;
    const ACTIVITY_WRITE_THROTTLE_MS = 45 * 1000;
    let myUserRef = null;
    let inactiveTimer = null;
    let presenceStarted = false;
    let lastPresenceWriteAt = 0;

    const clearInactiveTimer = () => {
      if (inactiveTimer) clearTimeout(inactiveTimer);
      inactiveTimer = null;
    };

    const stopPresence = () => {
      clearInactiveTimer();
      if (!myUserRef) return;
      myUserRef.remove().catch(() => {});
      try { myUserRef.onDisconnect().cancel(); } catch (e) {}
      myUserRef = null;
      presenceStarted = false;
      lastPresenceWriteAt = 0;
    };

    const startPresence = () => {
      if (presenceStarted || document.hidden) return;
      presenceStarted = true;
      myUserRef = onlineUsersRef.push();
      myUserRef.set({
        origem: getOrigemAcesso(),
        pagina: location.pathname + location.hash,
        userAgent: navigator.userAgent,
        active: true,
        timestamp: firebase.database.ServerValue.TIMESTAMP,
        lastSeen: firebase.database.ServerValue.TIMESTAMP
      });
      myUserRef.onDisconnect().remove();
      lastPresenceWriteAt = Date.now();
      scheduleIdleExpiration();
    };

    const markPresenceInactive = () => {
      if (!myUserRef) return;
      myUserRef.update({
        active: false,
        inactivePending: true,
        inactiveAt: firebase.database.ServerValue.TIMESTAMP
      }).catch(() => {});
    };

    const scheduleIdleExpiration = () => {
      clearInactiveTimer();
      if (!myUserRef) return;
      inactiveTimer = setTimeout(markPresenceInactive, INACTIVE_LIMIT_MS);
    };

    const touchPresence = ({ force = false, pagina = false } = {}) => {
      if (document.hidden) return;
      if (!myUserRef) {
        startPresence();
        return;
      }
      const agora = Date.now();
      scheduleIdleExpiration();
      if (!force && (agora - lastPresenceWriteAt) < ACTIVITY_WRITE_THROTTLE_MS) return;
      lastPresenceWriteAt = agora;
      const payload = {
        active: true,
        inactivePending: false,
        inactiveAt: null,
        hiddenAt: null,
        lastSeen: firebase.database.ServerValue.TIMESTAMP
      };
      if (pagina) payload.pagina = location.pathname + location.hash;
      myUserRef.update(payload).catch(() => {});
    };

    const scheduleInactiveRemoval = () => {
      clearInactiveTimer();
      if (!myUserRef) return;
      myUserRef.update({
        active: true,
        inactivePending: true,
        hiddenAt: firebase.database.ServerValue.TIMESTAMP,
        lastSeen: firebase.database.ServerValue.TIMESTAMP
      }).catch(() => {});
      inactiveTimer = setTimeout(stopPresence, INACTIVE_LIMIT_MS);
    };

    document.addEventListener("visibilitychange", () => {
      if (document.hidden) scheduleInactiveRemoval();
      else {
        clearInactiveTimer();
        if (myUserRef) {
          myUserRef.update({
            active: true,
            inactivePending: false,
            hiddenAt: null,
            lastSeen: firebase.database.ServerValue.TIMESTAMP
          }).catch(() => {});
          lastPresenceWriteAt = Date.now();
          scheduleIdleExpiration();
        } else {
          startPresence();
        }
      }
    });
    window.addEventListener("pagehide", stopPresence);
    window.addEventListener("beforeunload", stopPresence);

    connectedRef.on("value", (snap) => {
      if (snap.val() === true) startPresence();
    });

    ["click", "keydown", "wheel", "scroll", "touchstart", "pointerdown", "mousemove"].forEach((eventName) => {
      window.addEventListener(eventName, () => touchPresence(), { passive: true });
    });
    window.addEventListener("hashchange", () => touchPresence({ force: true, pagina: true }));
    window.addEventListener("popstate", () => touchPresence({ force: true, pagina: true }));
    window.addEventListener("focus", () => touchPresence({ force: true, pagina: true }));

    onlineUsersRef.on("value", (snapshot) => {
      const agora = Date.now();
      let userCount = 0;
      snapshot.forEach((child) => {
        const user = child.val() || {};
        const lastSeen = Number(user.lastSeen || user.timestamp || 0);
        const recente = Number.isFinite(lastSeen) && lastSeen > 0 && (agora - lastSeen) <= INACTIVE_LIMIT_MS;
        const ativo = user.active !== false && recente;
        if (ativo) userCount += 1;
      });

      contadorEl.textContent = userCount;
      if (iconeEl && userCount > contadorAnterior) {
        iconeEl.classList.add("icone-notificacao");
        setTimeout(() => {
          iconeEl.classList.remove("icone-notificacao");
          iconeEl.style.color = "";
        }, 5000);
      }
      contadorAnterior = userCount;
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", inicializarContadorOnline);
  } else {
    inicializarContadorOnline();
  }

  function detectarCanalAcesso() {
    const isStandalone =
      window.matchMedia?.("(display-mode: standalone)").matches ||
      window.matchMedia?.("(display-mode: fullscreen)").matches ||
      window.matchMedia?.("(display-mode: minimal-ui)").matches ||
      window.navigator.standalone === true; // iOS

    return isStandalone ? "App (PWA)" : "Site (Navegador)";
  }







  // Função para registrar o acesso diário
  function registrarAcesso() {
    const hoje = getHojeBR();


    // 1. IDENTIFICAR A ORIGEM (Prioridade: Link > App > Site)
    const origemLink = origemParametroAtual();
    const isApp = window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true;




    let origemFinal = "Site";
    if (origemLink) {
      origemFinal = origemLink; // Se tiver ?o=xxx, usa o que estiver escrito
    } else if (isApp) {
      origemFinal = "App"; // Se for o App instalado
    }

    const refTotal = firebase.database().ref(`acessosPorDia/${hoje}/total`);
    const refDetalhado = firebase.database().ref(`acessosPorDia/${hoje}/detalhados`).push();

    refTotal.transaction((acessos) => (acessos || 0) + 1);

    refTotal.transaction((acessos) => (acessos || 0) + 1);

    function salvarDados(info) {
      salvarOrigemCliqueLocal({
        ...info,
        origem: origemFinal,
        canal: detectarCanalAcesso()
      });
      refDetalhado.set({
        ip: info.ip || "sem_ip",
        cidade: info.city || "Desconhecida",
        estado: info.region || "UF",
        pais: info.country || "BR",
        provedor: info.provider || "Desconhecido",
        latitude: info.latitude || null,
        longitude: info.longitude || null,
        timezone: info.timezone || "Indefinido",
        horario: new Date().toLocaleTimeString(),
        navegador: navigator.userAgent,
        idioma: navigator.language,
        plataforma: navigator.platform,
        pagina: window.location.href,
        referrer: document.referrer || "acesso direto",
        // origem: new URLSearchParams(window.location.search).get("o") || "acesso direto",
        // SALVANDO A ORIGEM IDENTIFICADA
        origem: origemFinal,
        canal: detectarCanalAcesso(), // ✅ NOVO (Site vs App)
        tela: `${window.screen.width}x${window.screen.height}`,
        dispositivo: /Mobi|Android/i.test(navigator.userAgent) ? "mobile" : "desktop"
      });

      // NOVO: registrar usuário único
      if (info.ip) {
        const ipTratado = info.ip.replace(/\./g, "-");  // Substitui os pontos por hífens
        const refUsuarioUnico = firebase.database().ref(`usuariosUnicos/${hoje}/${ipTratado}`);
        refUsuarioUnico.set(true)
          .then(() => {
            console.log("Usuário único registrado:", ipTratado); // Log para confirmar
          })
          .catch(error => {
            console.error("Erro ao registrar IP no Firebase:", error);
          });

      }

    }

    // Tenta com ipwho.is
    fetch("https://ipwho.is/")
      .then((res) => res.json())
      .then((data) => {
        if (!data.success) throw new Error("Falhou no ipwho.is");
        salvarDados({
          ip: data.ip,
          city: data.city,
          region: data.region,
          country: data.country,
          provider: data.connection?.isp,
          latitude: data.latitude,
          longitude: data.longitude,
          timezone: data.timezone
        });
      })
      .catch(() => {
        // Fallback: tenta com ipapi.co
        fetch("https://ipapi.co/json/")
          .then((res) => res.json())
          .then((data) => {
            if (!data.city) throw new Error("Falhou no ipapi.co");
            salvarDados({
              ip: data.ip,
              city: data.city,
              region: data.region,
              country: data.country,
              provider: data.org,
              latitude: data.latitude,
              longitude: data.longitude,
              timezone: data.timezone
            });
          })
          .catch(() => {
            // Segundo fallback: ipinfo.io
            fetch("https://ipinfo.io/json?token=50e0b3cf789df2")
              .then((res) => res.json())
              .then((data) => {
                salvarDados({
                  ip: data.ip,
                  city: data.city,
                  region: data.region,
                  country: data.country,
                  provider: data.org,
                  latitude: data.loc?.split(',')[0],
                  longitude: data.loc?.split(',')[1],
                  timezone: data.timezone
                });
              })
              .catch((error) => {
                console.warn("Não foi possível obter localização:", error);
                salvarDados({});
              });
          });
      });
  }

