  // ============ PROMOÇÕES ============

  function chavePromocaoPublica(item = {}, contexto = {}) {
    const estabelecimento = [...chavesDonoPromocaoPublica(item, contexto)][0] || "";
    return `${estabelecimento}|${conteudoPromocaoPublica(item)}`;
  }

  function conteudoPromocaoPublica(item = {}) {
    const titulo = normalizeName(item.titulo || item.nome || item.name || "");
    const descricao = normalizeName(item.descricao || item.description || item.obs || item.observacoes || "");
    const imagem = normalizeName(item.imagem || item.image || item.imagemUrl || item.imageUrl || item.foto || item.fotoUrl || item.banner || "");
    const preco = normalizeName(item.preco || item.valor || item.price || "");
    const desconto = normalizeName(item.desconto || item.discount || "");
    const validade = normalizeName(item.validadeFim || item.validade || "");
    const fallbackId = normalizeName(item.id || "");
    return [
      titulo || fallbackId,
      preco,
      desconto,
      validade,
      imagem,
      descricao
    ].join("|");
  }

  function chavesDonoPromocaoPublica(item = {}, contexto = {}) {
    const valores = [
      contexto.estabelecimentoId,
      contexto.nomeNormalizado,
      contexto.estabelecimento,
      contexto.clienteId,
      contexto.clienteNome,
      item.estabelecimentoId,
      item.estabelecimento,
      item.clienteId,
      item.clienteNome,
      item.nomeCliente
    ];
    const chaves = new Set(valores.map((value) => normalizeName(value)).filter(Boolean));
    const alvo = [...chaves].find(Boolean);
    if (alvo && typeof encontrarCategoriaEstabelecimentoPublico === "function") {
      const encontrado = encontrarCategoriaEstabelecimentoPublico(alvo);
      if (encontrado?.estabelecimento) {
        chavesEstabelecimentoPublico(encontrado.estabelecimento).forEach((chave) => chaves.add(chave));
        const cliente = clientePublicoDoEstabelecimento(encontrado.estabelecimento);
        if (cliente) {
          [cliente.id, cliente.nome, cliente.name, cliente.nomeNormalizado].map((value) => normalizeName(value)).filter(Boolean).forEach((chave) => chaves.add(chave));
        }
      }
    }
    if (typeof window !== "undefined") {
      Object.entries(window.__clientesPublicosCache || {}).forEach(([id, cliente]) => {
        const aliases = [id, cliente?.nome, cliente?.name, cliente?.nomeNormalizado].map((value) => normalizeName(value)).filter(Boolean);
        if (!aliases.some((alias) => chaves.has(alias))) return;
        aliases.forEach((alias) => chaves.add(alias));
      });
    }
    return chaves;
  }

  function donosPromocaoRelacionados(a = new Set(), b = new Set()) {
    if (!a.size || !b.size) return false;
    return [...a].some((chaveA) => [...b].some((chaveB) => (
      chaveA === chaveB
      || (chaveA.length >= 4 && chaveB.length >= 4 && (chaveA.includes(chaveB) || chaveB.includes(chaveA)))
    )));
  }

  function deduplicarPromocoesPublicas(lista = []) {
    const vistosPorConteudo = new Map();
    return (lista || []).filter((item) => {
      const conteudo = conteudoPromocaoPublica(item);
      if (!conteudo.trim()) return true;
      const donos = chavesDonoPromocaoPublica(item);
      const vistos = vistosPorConteudo.get(conteudo) || [];
      if (vistos.some((anteriores) => donosPromocaoRelacionados(donos, anteriores))) return false;
      vistos.push(donos);
      vistosPorConteudo.set(conteudo, vistos);
      return true;
    });
  }

  function deduplicarPromocoesMesmoEstabelecimentoPublico(lista = []) {
    const vistos = new Set();
    return (lista || []).filter((item) => {
      const chave = conteudoPromocaoPublica(item);
      if (!chave.trim()) return true;
      if (vistos.has(chave)) return false;
      vistos.add(chave);
      return true;
    });
  }

  function renderAbaClientePublica({ target, label, icon, count = 0, active = false, tone = "blue", extra = "" } = {}) {
    const badge = Number(count || 0) > 0 ? `<span class="cliente-tab-badge">${Number(count)}</span>` : "";
    return `
      <button class="aba-tab cliente-tab-card ${active ? "active" : ""}" data-target="${target}" ${extra}>
        <span class="cliente-tab-icon cliente-tab-${tone}">
          <i class="${icon}"></i>
          ${badge}
        </span>
        <span class="cliente-tab-label">${label}</span>
      </button>
    `;
  }

  function tipoAbaClientePublica(target = "") {
    return String(target || "").split("-")[0] || "";
  }

  function ordenarAbasClientePublica(nav) {
    if (!nav) return;
    const ordem = {
      info: 0,
      produtos: 1,
      promocoes: 2,
      cardapio: 3,
      veiculos: 4,
      fotos: 5,
      imoveis: 6
    };
    [...nav.querySelectorAll(".aba-tab")].map((tab, index) => ({ tab, index }))
      .sort((a, b) => {
        const tipoA = tipoAbaClientePublica(a.tab.dataset.target);
        const tipoB = tipoAbaClientePublica(b.tab.dataset.target);
        return (ordem[tipoA] ?? 50) - (ordem[tipoB] ?? 50) || a.index - b.index;
      })
      .forEach(({ tab }) => nav.appendChild(tab));
  }

  function renderFuncionamentoClientePublico(establishment = {}, statusHtml = "") {
    const temHorarios = establishment.horarios && typeof establishment.horarios === "object";
    const temTexto = !temHorarios && establishment.hours;
    if (!establishment.funcionamento24Horas && !temHorarios && !temTexto && !statusHtml) return "";
    const statusBase = statusHtml || (establishment.funcionamento24Horas
      ? `<span class='status-tag vinte-quatro-horas'>ABERTO 24 HORAS</span>`
      : `<span class='status-tag aberto'>HORARIO</span>`);
    const status = statusBase.match(/<span class=['"]status-tag[^>]*>.*?<\/span>/i)?.[0] || statusBase;
    const proximo = statusBase.match(/<span class=['"]proximo-horario['"]>(.*?)<\/span>/i)?.[1] || "";
    const resumo = proximo || (statusBase.includes("FECHADO") ? "Consulte os horarios" : "Ver todos os horarios");
    if (temHorarios) {
      return `
        <details class="cliente-funcionamento-card">
          <summary>
            <span class="cliente-funcionamento-status">${status}</span>
            <span class="cliente-funcionamento-resumo">
              <strong>${resumo}</strong>
              <small>Ver todos os horarios</small>
            </span>
            <i class="fa-solid fa-chevron-right cliente-funcionamento-seta"></i>
          </summary>
          <div class="cliente-funcionamento-detalhes">
            ${renderHorariosFuncionamento(establishment.horarios)}
          </div>
        </details>
      `;
    }
    return `
      <div class="cliente-funcionamento-card cliente-funcionamento-card-static">
        <div class="cliente-funcionamento-status">${status}</div>
        <div class="cliente-funcionamento-resumo">
          <strong>${escapePromoHtml(temTexto ? establishment.hours : "Funcionamento 24 horas")}</strong>
        </div>
      </div>
    `;
  }

  // Coleta TODAS as promoções percorrendo categories/establishments
  function coletarTodasPromocoes() {
    const itens = [];
    const vistos = new Set();
    let ordem = 0;
    const adicionarPromocao = (p = {}, contexto = {}) => {
      if (p && p.ativo === false) return;
      if (p && p.status === "inativo") return;
      const idEst = normalizeName(contexto.estabelecimentoId || contexto.nomeNormalizado || contexto.estabelecimento || "");
      const nomeEst = contexto.estabelecimento || "";
      const promoId = p.id || "";
      const tituloPromo = p.titulo || p.nome || p.name || "";
      const chavePromo = chavePromocaoPublica(p, contexto);
      if (chavePromo && vistos.has(chavePromo)) return;
      if (chavePromo) vistos.add(chavePromo);
      itens.push({
        ordem: ordem++,
        id: promoId || `promo_${idEst || "cliente"}_${ordem}`,
        estabelecimento: nomeEst,
        estabelecimentoId: idEst,
        categoria: contexto.categoria || p.categoria || "",
        titulo: tituloPromo,
        descricao: p.descricao || p.description || p.obs || [p.volume, p.embalagem].filter(Boolean).join(" + "),
        volume: p.volume || "",
        embalagem: p.embalagem || "",
        preco: p.preco,
        desconto: p.desconto || p.discount || "",
        tipoOferta: p.tipoOferta || "",
        entregaRetirada: p.entregaRetirada || "",
        faixaPreco: p.faixaPreco || "",
        modoPreco: p.modoPreco || "",
        destaque: p.destaque || p.badge || "",
        tipoDesconto: p.tipoDesconto || p.tipo || "",
        valorTexto: p.valorTexto || p.valor || "",
        precoAntigo: p.precoAntigo || null,
        unidade: p.unidade || "",
        imagem: p.imagem || p.image || p.imagemUrl || p.imageUrl || p.foto || p.fotoUrl || p.banner || "",
        logo: p.logo || p.logoUrl || p.perfil || p.perfilUrl || contexto.logo || "",
        validadeInicio: p.validadeInicio || p.validade || null,
        validadeFim: p.validadeFim || null,
        diasSemana: normalizarDiasSemanaPromocao(p.diasSemana || p.dias || p.recorrenciaDias || p.diaSemana),
        obs: p.obs || p.observacoes || "",
        instagramMensagem: p.instagramMensagem || p.mensagemInstagram || p.chamadaInstagram || contexto.instagramMensagem || "Siga no Instagram e fique por dentro das novidades!",
        contact: contexto.contact || "",
        instagram: contexto.instagram || "",
        criadoEm: p.criadoEm || p.createdAt || ""
      });
    };
    (categories || []).forEach(cat => {
      (cat.establishments || []).forEach(est => {
        const nomeEst = est.name;
        const idEst = normalizeName(est.nomeNormalizado || nomeEst);
        const statusEst = statusEstabelecimentos[idEst] || statusEstabelecimentos[normalizeName(nomeEst)];
        if (statusEst && statusEst !== "s") return;
        const lista = est.promocoes || est.promotions || [];
        lista.forEach(p => adicionarPromocao(p, {
          estabelecimento: nomeEst,
          estabelecimentoId: idEst,
          categoria: cat.title || "",
          logo: est.logo || est.logoUrl || est.profileImage || est.perfil || est.imagemPerfil || est.image || "",
          instagramMensagem: est.instagramMensagem,
          contact: getPrimeiroContato(est.contact) || "",
          instagram: est.instagram || ""
        }));
      });
    });
    Object.entries((typeof window !== "undefined" ? window.__clientesPublicosCache : null) || {}).forEach(([clienteId, cliente]) => {
      const lista = Array.isArray(cliente?.promocoes)
        ? cliente.promocoes
        : Object.entries(cliente?.promocoes || {}).map(([id, value]) => (
          value && typeof value === "object" ? { id, ...value } : { id, titulo: value }
        ));
      lista.forEach((p) => {
        adicionarPromocao(p, {
          estabelecimento: cliente.nome || cliente.name || clienteId,
          estabelecimentoId: clienteId,
          nomeNormalizado: cliente.nomeNormalizado || clienteId,
          categoria: cliente.categoria || "",
          logo: cliente.imagem || cliente.image || "",
          instagramMensagem: cliente.instagramMensagem,
          contact: getPrimeiroContato(cliente.contato || cliente.whatsapp || "") || "",
          instagram: cliente.instagram || ""
        });
      });
    });
    return deduplicarPromocoesPublicas(itens);
  }

  function chavePublicaGenericaEstabelecimento(value = "") {
    const key = normalizeName(value);
    if (!key) return true;
    const compacta = key.replace(/[^a-z0-9]/g, "");
    const genericas = new Set([
      "automovel",
      "automoveis",
      "auto",
      "autos",
      "carro",
      "carros",
      "carveiculos",
      "deautomovel",
      "deautomoveis",
      "decarro",
      "decarros",
      "deveiculo",
      "deveiculos",
      "loja",
      "lojas",
      "outro",
      "outros",
      "outroscliente",
      "outrocliente",
      "revenda",
      "revendade",
      "revendadeautomovel",
      "revendadeautomoveis",
      "revendadecarro",
      "revendadecarros",
      "revendadeveiculo",
      "revendadeveiculos",
      "revendaveiculo",
      "veiculo",
      "veiculos"
    ]);
    return genericas.has(key) || genericas.has(compacta);
  }

  function chavesEstabelecimentoPublico(est = {}) {
    const aliases = est.aliases || est.apelidos || [];
    const aliasValues = Array.isArray(aliases)
      ? aliases
      : [...Object.keys(aliases || {}), ...Object.values(aliases || {})];
    const principais = [
      est.id,
      est.clienteId,
      est.clienteNome,
      est.nomeCliente,
      est.nomeNormalizado,
      est.__adminOriginalSlug,
      est.__adminOriginalName,
      est.name,
      est.nome
    ].map((value) => normalizeName(value)).filter(Boolean);
    const aliasesEspecificos = aliasValues
      .map((value) => normalizeName(value))
      .filter((value) => value && !chavePublicaGenericaEstabelecimento(value));
    return [...new Set([...principais, ...aliasesEspecificos])];
  }

  function usuariosPublicosDoCliente(clienteId = "") {
    const id = String(clienteId || "").trim();
    if (!id || typeof window === "undefined") return [];
    const usuarios = window.__usuariosPublicosCache || {};
    return Object.values(usuarios).filter((user) => (
      user
      && user.status !== "inativo"
      && user.status !== "bloqueado"
      && String(user.clienteId || "") === id
    ));
  }

  function clientePublicoDoEstabelecimento(est = {}) {
    if (est.__clientePublico) return est.__clientePublico;
    const clientes = typeof window !== "undefined" ? (window.__clientesPublicosCache || {}) : {};
    const chaves = new Set(chavesEstabelecimentoPublico(est));
    const cliente = Object.entries(clientes).map(([id, value]) => ({ id, ...value })).find((item) => (
      chaves.has(normalizeName(item.id))
      || chaves.has(normalizeName(item.nome))
      || chaves.has(normalizeName(item.name))
      || chaves.has(normalizeName(item.nomeNormalizado))
    )) || null;
    if (cliente) est.__clientePublico = cliente;
    return cliente;
  }

  function moduloClientePublicoAtivo(est = {}, modulo = "") {
    const cliente = clientePublicoDoEstabelecimento(est) || {};
    const usuarios = usuariosPublicosDoCliente(cliente.id || est.clienteId || "");
    const permissoes = usuarios.reduce((acc, user) => {
      Object.entries(user.permissoes || {}).forEach(([key, value]) => {
        acc[key] = Boolean(acc[key] || value);
      });
      return acc;
    }, {
      ...(cliente.permissoes || {}),
      ...(est.permissoes || {})
    });
    if (Object.prototype.hasOwnProperty.call(permissoes, modulo)) return Boolean(permissoes[modulo]);
    if (!usuarios.length && !Object.keys(permissoes).length) return true;
    if (modulo === "veiculos") return estabelecimentoPublicoEhDeVeiculos({ ...est, ...cliente });
    if (modulo === "imoveis") {
      const texto = normalizeName([
        est.categoria,
        est.categoriaId,
        est.__categoriaPublica,
        cliente.categoria,
        cliente.categoriaId,
        cliente.tipo,
        cliente.tipoCliente
      ].filter(Boolean).join(" "));
      return /imovel|imoveis|imobili|corretor/.test(texto);
    }
    return Boolean(permissoes[modulo]);
  }

  async function carregarModulosClientesPublicos() {
    if (typeof window === "undefined") return;
    if (window.__clientesPublicosCache && window.__usuariosPublicosCache) return;
    if (window.__modulosClientesPublicosPromise) return window.__modulosClientesPublicosPromise;
    window.__modulosClientesPublicosPromise = (async () => {
      const dbAdmin = await esperarFirebaseDatabase();
      if (!dbAdmin) return;
      const clientesSnap = await dbAdmin.ref("clientes").once("value");
      window.__clientesPublicosCache = window.__clientesPublicosCache || clientesSnap.val() || {};
      const usuariosSnap = await dbAdmin.ref("usuariosByUid").once("value").catch((error) => {
        console.warn("Permissoes publicas dos usuarios indisponiveis; abas serao liberadas por itens vinculados.", error);
        return null;
      });
      window.__usuariosPublicosCache = window.__usuariosPublicosCache || usuariosSnap?.val?.() || {};
    })().catch((error) => {
      console.warn("Nao foi possivel carregar modulos publicos dos clientes.", error);
    });
    return window.__modulosClientesPublicosPromise;
  }

  function encontrarCategoriaEstabelecimentoPublico(chave = "") {
    const alvo = normalizeName(chave);
    if (!alvo) return null;
    const corresponde = (item) => {
      if (item === alvo) return true;
      if (item.length < 12 || alvo.length < 12) return false;
      const menor = item.length < alvo.length ? item : alvo;
      const maior = item.length < alvo.length ? alvo : item;
      if (chavePublicaGenericaEstabelecimento(menor)) return false;
      if (menor.length < 12) return false;
      if (maior.length - menor.length > 24) return false;
      return maior.startsWith(menor) || maior.endsWith(menor);
    };
    for (const categoria of categories || []) {
      for (const estabelecimento of categoria.establishments || []) {
        const chaves = chavesEstabelecimentoPublico(estabelecimento);
        const encontrou = chaves.some(corresponde);
        if (encontrou) return { categoria, estabelecimento };
      }
    }
    return null;
  }

  function itemPertenceAoEstabelecimentoPublico(item = {}, est = {}) {
    const chaves = new Set(chavesEstabelecimentoPublico(est));
    if (!chaves.size) return false;
    const cliente = clientePublicoDoEstabelecimento(est) || {};
    [
      cliente.id,
      cliente.nome,
      cliente.name,
      cliente.nomeNormalizado
    ].map(normalizeName).filter(Boolean).forEach((chave) => chaves.add(chave));
    const candidatos = [
      item.estabelecimentoId,
      item.clienteId,
      item.idCliente,
      item.clienteSlug,
      item.clienteNome,
      item.nomeCliente,
      item.estabelecimento,
      item.estabelecimentoNome,
      item.nomeEstabelecimento,
      item.vendedor,
      item.loja,
      item.lojaNome,
      item.nomeLoja,
      item.Loja,
      item.NomeLoja,
      item.LojaNome,
      item.empresa,
      item.Empresa,
      item.anunciante,
      item.Anunciante,
      item.corretor,
      item.raw?.clienteId,
      item.raw?.clienteNome,
      item.raw?.estabelecimentoId,
      item.raw?.estabelecimento,
      ...(Array.isArray(item.corretores) ? item.corretores : [])
    ].map(normalizeName).filter(Boolean);
    const chavesFortes = [...chaves].filter((chave) => chave.length >= 12);
    const correspondeComoAliasForte = (valor, chave) => {
      if (valor === chave) return true;
      if (valor.length < 12 || chave.length < 12) return false;
      const menor = valor.length < chave.length ? valor : chave;
      const maior = valor.length < chave.length ? chave : valor;
      if (menor.length < 12) return false;
      if (chavePublicaGenericaEstabelecimento(menor)) return false;
      const diferenca = maior.length - menor.length;
      if (diferenca > 24) return false;
      return maior.startsWith(menor) || maior.endsWith(menor);
    };
    return candidatos.some((valor) => {
      if (chaves.has(valor)) return true;
      return chavesFortes.some((chave) => correspondeComoAliasForte(valor, chave));
    });
  }

  function automoveisDoEstabelecimentoPublico(est = {}, autos = []) {
    const externos = (autos || []).filter((item) => (
      item.status !== "inativo"
      && item.ativo !== false
      && itemPertenceAoEstabelecimentoPublico(item, est)
    ));
    const internosOrigem = est.automoveis || est.veiculos || est.vehicles || est.cars || [];
    const internos = (Array.isArray(internosOrigem)
      ? internosOrigem
      : Object.entries(internosOrigem || {}).map(([id, value]) => (
        value && typeof value === "object" ? { id, ...value } : { id, modelo: value }
      ))
    )
      .map((item, index) => automovelDeRegistro({
        ...item,
        clienteId: item.clienteId || est.clienteId || "",
        clienteNome: item.clienteNome || est.clienteNome || est.name || est.nome || "",
        estabelecimentoId: item.estabelecimentoId || est.nomeNormalizado || est.id || "",
        loja: item.loja || item.vendedor || est.name || est.nome || ""
      }, item.id || `veiculo-${normalizeName(est.name || est.nome || "loja")}-${index}`))
      .filter((item) => item.status !== "inativo" && item.ativo !== false);
    const porId = new Map();
    [...externos, ...internos].forEach((item) => {
      const id = String(item.id || `${item.clienteId || item.clienteNome || ""}-${item.marca || ""}-${item.modelo || ""}-${item.ano || ""}`);
      if (!porId.has(id)) porId.set(id, item);
    });
    return Array.from(porId.values());
  }

  function estabelecimentoPublicoEhDeVeiculos(est = {}) {
    const texto = normalizeName([
      est.categoria,
      est.categoriaId,
      est.tipoCliente,
      est.tipo,
      est.__categoriaPublica,
      est.name,
      est.nome
    ].filter(Boolean).join(" "));
    return /automovel|automoveis|veiculo|veiculos|revenda|carro|moto/.test(texto);
  }

  function produtosDoEstabelecimentoPublico(est = {}) {
    const cliente = clientePublicoDoEstabelecimento(est) || {};
    const origem = cliente.produtos || est.produtos || cliente.products || est.products || cliente.itens || est.itens || cliente.items || est.items || [];
    const lista = Array.isArray(origem)
      ? origem
      : Object.entries(origem || {}).map(([id, value]) => (
        value && typeof value === "object" ? { id, ...value } : { id, nome: value }
      ));
    return lista
      .map((item, index) => {
        const imagens = [
          ...(Array.isArray(item.imagens) ? item.imagens : []),
          item.imagem,
          item.image,
          item.foto,
          item.fotoUrl,
          item.imagemUrl
        ].map((url) => String(url || "").trim()).filter(Boolean).slice(0, 4);
        return {
          id: item.id || `produto-${normalizeName(est.name || "loja")}-${index}`,
          titulo: item.titulo || item.nome || item.name || item.produto || "Produto",
          descricao: item.descricao || item.description || item.obs || item.observacoes || "",
          preco: item.preco || item.valor || item.price || "",
          mostrarPreco: item.mostrarPreco === false ? false : true,
          imagem: imagens[0] || "",
          imagens,
          observacoes: item.observacoes || item.obs || item.detalhes || "",
          categoria: item.categoria || item.tipo || "",
          setor: item.setor || item.segmento || item.departamento || "",
          marca: item.marca || item.brand || "",
          modelo: item.modelo || item.model || "",
          tipoMedida: item.tipoMedida || item.measureType || (item.volume ? "Volume" : item.medida ? "Medida" : item.tamanho ? "Tamanho" : ""),
          tamanho: item.tamanho || item.medida || item.volume || item.size || "",
          cores: item.cores || item.cor || item.colors || "",
          variacoes: item.variacoes || item.variacao || item.variations || "",
          condicao: item.condicao || item.condition || "",
          disponibilidade: item.disponibilidade || item.availability || "",
          entregaRetirada: item.entregaRetirada || item.fulfillment || item.entrega || "",
          informacoesEspecificas: item.informacoesEspecificas || item.infoEspecificas || item.informacoes || "",
          destaque: item.destaque === true || item.produtoDestaque === true,
          ordem: item.ordem || item.ordemExibicao || item.order || "",
          contato: item.contato || item.whatsapp || cliente.whatsapp || cliente.contact || est.whatsapp || est.contact || "",
          status: item.status || "ativo",
          ativo: item.ativo === false ? false : true,
          createdAt: item.createdAt || item.criadoEm || "",
          updatedAt: item.updatedAt || item.dataAtualizacao || ""
        };
      })
      .filter((item) => item.status !== "inativo" && item.ativo !== false && item.titulo)
      .sort((a, b) => {
        if (Boolean(a.destaque) !== Boolean(b.destaque)) return a.destaque ? -1 : 1;
        const ordemA = Number(a.ordem);
        const ordemB = Number(b.ordem);
        const temOrdemA = Number.isFinite(ordemA) && ordemA > 0;
        const temOrdemB = Number.isFinite(ordemB) && ordemB > 0;
        if (temOrdemA || temOrdemB) return (temOrdemA ? ordemA : 999999) - (temOrdemB ? ordemB : 999999);
        return novidadeCidadeMs(b.updatedAt || b.createdAt) - novidadeCidadeMs(a.updatedAt || a.createdAt);
      });
  }

  function normalizarPromocoesPublicas(origem = [], contexto = {}) {
    const lista = Array.isArray(origem)
      ? origem
      : Object.entries(origem || {}).map(([id, value]) => (
        value && typeof value === "object" ? { id, ...value } : { id, titulo: value }
      ));
    return lista
      .map((item, index) => ({
        id: item.id || `promo-${normalizeName(contexto.estabelecimentoId || contexto.estabelecimento || "loja")}-${index}`,
        estabelecimento: contexto.estabelecimento || item.estabelecimento || "",
        estabelecimentoId: contexto.estabelecimentoId || item.estabelecimentoId || "",
        categoria: contexto.categoria || item.categoria || "",
        titulo: item.titulo || item.nome || item.name || "Promocao",
        descricao: item.descricao || item.description || item.obs || "",
        preco: item.preco || item.valor || item.price || "",
        desconto: item.desconto || item.discount || "",
        tipoOferta: item.tipoOferta || "",
        entregaRetirada: item.entregaRetirada || "",
        faixaPreco: item.faixaPreco || "",
        modoPreco: item.modoPreco || "",
        precoAntigo: item.precoAntigo || item.precoReal || item.valorReal || item.precoOriginal || null,
        unidade: item.unidade || "",
        volume: item.volume || "",
        embalagem: item.embalagem || "",
        imagem: item.imagem || item.image || item.foto || item.fotoUrl || item.imagemUrl || "",
        imagens: [
          ...(Array.isArray(item.imagens) ? item.imagens : []),
          item.imagem,
          item.image,
          item.foto,
          item.fotoUrl,
          item.imagemUrl
        ].map((url) => String(url || "").trim()).filter(Boolean).slice(0, 4),
        validadeInicio: item.validadeInicio || item.validade || null,
        validadeFim: item.validadeFim || null,
        diasSemana: normalizarDiasSemanaPromocao(item.diasSemana || item.dias || item.recorrenciaDias || item.diaSemana),
        obs: item.obs || item.observacoes || "",
        contato: item.contato || item.contact || item.whatsapp || contexto.contact || contexto.contato || "",
        whatsapp: item.whatsapp || contexto.whatsapp || contexto.contact || contexto.contato || "",
        telefone: item.telefone || contexto.telefone || "",
        instagram: item.instagram || contexto.instagram || "",
        ativo: item.ativo === false ? false : true,
        status: item.status || "ativo"
      }))
      .filter((item) => item.status !== "inativo" && item.ativo !== false && item.titulo);
  }

  function promocoesDoEstabelecimentoPublico(est = {}) {
    const chaves = new Set(chavesEstabelecimentoPublico(est));
    const cliente = clientePublicoDoEstabelecimento(est) || {};
    const promocoesCliente = normalizarPromocoesPublicas(cliente.promocoes || est.promocoes || est.promotions || [], {
      estabelecimento: est.name || cliente.nome || cliente.name || "",
      estabelecimentoId: normalizeName(cliente.id || est.clienteId || cliente.nomeNormalizado || est.nomeNormalizado || est.name || ""),
      categoria: cliente.categoria || est.categoria || "",
      contact: getPrimeiroContato(cliente.contato || cliente.whatsapp || est.contact || est.whatsapp || est.telefone || "") || "",
      whatsapp: cliente.whatsapp || est.whatsapp || "",
      telefone: cliente.telefone || est.telefone || "",
      instagram: cliente.instagram || est.instagram || ""
    });
    const porId = new Map();
    [...coletarTodasPromocoes(), ...promocoesCliente]
      .filter((promo) => chaves.has(normalizeName(promo.estabelecimentoId)) || chaves.has(normalizeName(promo.estabelecimento)))
      .filter((promo) => !promoExpirada(promo) && promoDisponivelHoje(promo))
      .forEach((promo) => {
        const id = chavePromocaoPublica(promo) || String(promo.id || `${promo.estabelecimentoId}-${promo.titulo}`);
        if (!porId.has(id)) porId.set(id, promo);
      });
    return deduplicarPromocoesMesmoEstabelecimentoPublico(Array.from(porId.values()));
  }

  function produtoPrecoPublico(item = {}, tipo = "produto") {
    if (tipo === "produto" && item.mostrarPreco === false) return "Consultar";
    const preco = formatarMoedaPromo(item.preco);
    if (preco) return preco;
    return tipo === "produto" ? "Consultar" : "";
  }

  function produtoWhatsappLink(item = {}, tipo = "produto") {
    const contato = somenteDigitos(item.contato || item.whatsapp || item.telefone || "");
    if (contato.length < 10) return "";
    const label = tipo === "promocao" ? "a promocao" : "o produto";
    const mensagem = `Ola, vi no Ola Carlopolis ${label}: ${item.titulo || item.nome || "Produto"}. Gostaria de mais informacoes.`;
    return `https://api.whatsapp.com/send?phone=${numeroWhatsAppBrasil(contato)}&text=${encodeURIComponent(mensagem)}`;
  }

  function produtoMedidaLabel(item = {}) {
    const label = item.tipoMedida || "";
    return ["Tamanho", "Medida", "Volume"].includes(label) ? label : "Tamanho";
  }

  function renderProdutoCardEstabelecimento(item = {}, tipo = "produto") {
    const isPromocao = tipo === "promocao";
    const preco = produtoPrecoPublico(item, tipo);
    const precoAntigo = formatarMoedaPromo(item.precoAntigo || item.precoReal || item.valorReal || item.precoOriginal || "");
    const titulo = escapePromoHtml(item.titulo || "Produto");
    const descricao = escapePromoHtml(item.descricao || item.observacoes || "");
    const dataPromocaoBR = (value) => {
      const parts = String(value || "").split("-");
      return parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : String(value || "");
    };
    const infoPromocao = [
      item.validadeFim ? `Valido ate ${dataPromocaoBR(item.validadeFim)}` : "",
      item.desconto ? `Desconto: ${item.desconto}` : "",
      item.entregaRetirada || ""
    ].filter(Boolean).join(" | ");
    const setorCategoria = isPromocao ? "Promocao" : [item.setor, item.categoria].filter(Boolean).join(" / ");
    const whatsapp = produtoWhatsappLink(item, tipo);
    const id = String(item.id || `produto-${normalizeName(item.titulo || item.nome || "item")}`);
    const cacheKey = `${tipo}:${id}`;
    if (typeof window !== "undefined") {
      window.__lojaProdutosDetalhes = window.__lojaProdutosDetalhes || {};
      window.__lojaProdutosDetalhes[cacheKey] = { ...item, id };
    }
    return `
      <article class="loja-produto-card loja-card-produto ${isPromocao ? "loja-card-promocao" : ""}" data-loja-produto="${escapePromoHtml(id)}" data-loja-produto-tipo="${tipo}" data-loja-produto-key="${escapePromoHtml(cacheKey)}">
        <div class="loja-produto-card-body">
          <div class="loja-produto-media">
              ${item.imagem
                ? `<img src="${escapePromoHtml(item.imagem)}" alt="${titulo}" loading="lazy">`
                : `<div class="loja-produto-sem-imagem">Imagem do produto</div>`}
              ${isPromocao ? `<span class="loja-produto-badge loja-promocao-badge">Promoção</span>` : (item.destaque ? `<span class="loja-produto-badge">Destaque</span>` : "")}
          </div>
          <div class="loja-produto-info">
            ${setorCategoria ? `<div class="loja-produto-categoria">${escapePromoHtml(setorCategoria)}</div>` : ""}
            <div class="loja-produto-nome">${titulo}</div>
            ${descricao ? `<div class="loja-produto-descricao">${descricao}</div>` : ""}
            ${isPromocao && infoPromocao ? `<div class="loja-produto-promocao-info">${escapePromoHtml(infoPromocao)}</div>` : ""}
          </div>
          <div class="loja-produto-preco ${isPromocao ? "loja-promocao-preco" : ""}">
            ${isPromocao && precoAntigo ? `<small>De <s>${escapePromoHtml(precoAntigo)}</s></small>` : ""}
            <span>${escapePromoHtml(preco || (isPromocao ? "Ver promoção" : "Ver detalhes"))}</span>
          </div>
          ${(tipo === "produto" || isPromocao) ? (whatsapp
            ? `<a class="loja-produto-interesse" href="${escapePromoHtml(whatsapp)}" target="_blank" rel="noopener noreferrer"><i class="fa-brands fa-whatsapp"></i> Tenho interesse</a>`
            : `<button type="button" class="loja-produto-interesse is-disabled" disabled>Tenho interesse</button>`) : ""}
        </div>
      </article>
    `;
  }

  function renderFotoCardEstabelecimento(est = {}, img = "", index = 0) {
    const nome = est.name || est.nome || "Cliente";
    const descricao = est.novidadesDescriptions?.[index] || est.descricoesFotos?.[index] || "";
    const slug = normalizeName(nome);
    const cacheKey = `${slug}:${index}`;
    if (typeof window !== "undefined") {
      window.__lojaFotosDetalhes = window.__lojaFotosDetalhes || {};
      window.__lojaFotosGrupos = window.__lojaFotosGrupos || {};
      window.__lojaFotosGrupos[slug] = {
        nome,
        imagens: Array.isArray(est.novidadesImages) ? est.novidadesImages : [],
        descricoes: Array.isArray(est.novidadesDescriptions) ? est.novidadesDescriptions : []
      };
      window.__lojaFotosDetalhes[cacheKey] = { slug, index, img, descricao };
    }
    return `
      <article class="loja-foto-card loja-card-foto" data-loja-foto="${escapePromoHtml(cacheKey)}">
        <div class="loja-foto-media">
          <img src="${escapePromoHtml(img)}" alt="Foto ${index + 1} de ${escapePromoHtml(nome)}" loading="lazy" decoding="async">
        </div>
        <div class="loja-foto-info">
          <strong>Foto ${index + 1}</strong>
          ${descricao ? `<p>${escapePromoHtml(descricao)}</p>` : `<p>${escapePromoHtml(nome)}</p>`}
        </div>
      </article>
    `;
  }

  function abrirModalFotosEstabelecimentoPublico(grupo = {}, initialIndex = 0) {
    const imagens = Array.isArray(grupo.imagens) ? grupo.imagens.filter(Boolean) : [];
    if (!imagens.length) return;
    document.querySelectorAll(".modal-fotos-overlay").forEach((el) => el.remove());
    const descricoes = Array.isArray(grupo.descricoes) ? grupo.descricoes : [];
    const ordenadas = imagens.map((img, index) => ({ img, index }))
      .sort((a, b) => (a.index === initialIndex ? -1 : b.index === initialIndex ? 1 : a.index - b.index));
    const html = `
      <div class="modal-fotos-overlay">
        <div class="modal-fotos">
          <button class="close-modal-fotos" aria-label="Fechar">&times;</button>
          <h2>Fotos de ${escapePromoHtml(grupo.nome || "cliente")}</h2>
          <div class="modal-fotos-imgs">
            ${ordenadas.map(({ img, index }) => `
              <div>
                <img src="${escapePromoHtml(img)}" alt="Foto ${index + 1}" loading="lazy">
                ${descricoes[index] ? `<div>${escapePromoHtml(descricoes[index])}</div>` : ""}
              </div>
            `).join("")}
          </div>
        </div>
      </div>
    `;
    document.body.insertAdjacentHTML("beforeend", html);
    const overlay = document.querySelector(".modal-fotos-overlay");
    overlay?.querySelector(".close-modal-fotos")?.addEventListener("click", () => overlay.remove());
    overlay?.addEventListener("click", (event) => {
      if (event.target === overlay) overlay.remove();
    });
  }

  function abrirModalProdutoEstabelecimento(item = {}, tituloPadrao = "Produto") {
    document.querySelector(".loja-produto-modal")?.remove();
    const titulo = item.titulo || tituloPadrao;
    const isProduto = normalizeName(tituloPadrao || "").includes("produto");
    const isPromocao = normalizeName(tituloPadrao || "").includes("promocao");
    const preco = produtoPrecoPublico(item, isProduto ? "produto" : "promocao");
    const whatsapp = (isProduto || isPromocao) ? produtoWhatsappLink(item, isPromocao ? "promocao" : "produto") : "";
    const imagensProduto = [
      ...(Array.isArray(item.imagens) ? item.imagens : []),
      ...(Array.isArray(item.fotos) ? item.fotos : []),
      item.imagem,
      item.image,
      item.foto,
      item.banner
    ].map((img) => String(img || "").trim()).filter(Boolean).filter((img, index, arr) => arr.indexOf(img) === index).slice(0, 4);
    const detalheLinha = (label, value, icon = "fa-solid fa-circle-info") => (
      value ? `<p class="imovel-detalhes-endereco"><i class="${icon}"></i><span><strong>${escapePromoHtml(label)}:</strong> ${escapePromoHtml(value)}</span></p>` : ""
    );
    const detalhesProdutoHtml = [
      detalheLinha("Marca", item.marca, "fa-solid fa-copyright"),
      detalheLinha("Modelo", item.modelo, "fa-solid fa-barcode"),
      detalheLinha(produtoMedidaLabel(item), item.tamanho, "fa-solid fa-ruler-combined"),
      detalheLinha("Cores disponiveis", item.cores, "fa-solid fa-palette"),
      detalheLinha("Variacoes", item.variacoes, "fa-solid fa-layer-group"),
      detalheLinha("Condicao", item.condicao, "fa-solid fa-certificate"),
      detalheLinha("Disponibilidade", item.disponibilidade, "fa-solid fa-circle-check"),
      detalheLinha("Entrega ou retirada", item.entregaRetirada, "fa-solid fa-truck"),
      item.informacoesEspecificas ? `<p>${escapePromoHtml(item.informacoesEspecificas)}</p>` : ""
    ].filter(Boolean).join("");
    const modal = document.createElement("div");
    modal.className = "imovel-detalhes-modal loja-produto-modal";
    modal.innerHTML = `
      <section class="imovel-detalhes-dialog loja-produto-dialog" role="dialog" aria-modal="true" aria-label="${escapePromoHtml(titulo)}">
        <button type="button" class="imovel-detalhes-fechar loja-produto-fechar" aria-label="Fechar">&times;</button>
        <div class="imovel-detalhes-media loja-produto-media">
          ${imagensProduto.length ? `
            <div class="loja-produto-modal-galeria" data-produto-galeria>
              <img class="loja-produto-modal-img" src="${escapePromoHtml(imagensProduto[0])}" alt="${escapePromoHtml(titulo)} - imagem 1" data-produto-galeria-img loading="lazy">
              ${imagensProduto.length > 1 ? `
                <button type="button" class="loja-produto-galeria-seta anterior" data-produto-galeria-prev aria-label="Imagem anterior"><i class="fa-solid fa-chevron-left"></i></button>
                <button type="button" class="loja-produto-galeria-seta proxima" data-produto-galeria-next aria-label="Proxima imagem"><i class="fa-solid fa-chevron-right"></i></button>
                <span class="loja-produto-galeria-contador" data-produto-galeria-count>1/${imagensProduto.length}</span>
              ` : ""}
            </div>
          ` : `<div class="imovel-detalhes-sem-foto"><i class="fa-solid fa-box-open"></i></div>`}
        </div>
        <div class="imovel-detalhes-conteudo">
          <div class="imovel-detalhes-topo">
            <div>
              <h2>${escapePromoHtml(titulo)}</h2>
              ${[item.setor, item.categoria].filter(Boolean).length ? `<p class="imovel-detalhes-endereco"><i class="fa-solid fa-tag"></i><span>${escapePromoHtml([item.setor, item.categoria].filter(Boolean).join(" / "))}</span></p>` : ""}
            </div>
            ${preco ? `<div class="imovel-detalhes-financeiro"><strong class="imovel-detalhes-valor">${escapePromoHtml(preco)}</strong></div>` : ""}
          </div>
          ${(item.descricao || item.observacoes || item.obs) ? `
            <section class="imovel-detalhes-descricao">
              <div class="imovel-detalhes-descricao-titulo"><i class="fa-solid fa-align-left"></i><span>Detalhes</span></div>
              ${item.descricao ? `<p>${escapePromoHtml(item.descricao)}</p>` : ""}
              ${item.observacoes ? `<p>${escapePromoHtml(item.observacoes)}</p>` : ""}
              ${!item.observacoes && item.obs ? `<p>${escapePromoHtml(item.obs)}</p>` : ""}
            </section>
          ` : ""}
          ${isProduto && detalhesProdutoHtml ? `
            <section class="imovel-detalhes-descricao">
              <div class="imovel-detalhes-descricao-titulo"><i class="fa-solid fa-list-check"></i><span>Informacoes do produto</span></div>
              ${detalhesProdutoHtml}
            </section>
          ` : ""}
          ${(isProduto || isPromocao) && whatsapp ? `<a class="auto-whatsapp-button loja-produto-whatsapp" href="${escapePromoHtml(whatsapp)}" target="_blank" rel="noopener noreferrer"><i class="fa-brands fa-whatsapp"></i> Tenho interesse</a>` : ""}
        </div>
      </section>
    `;
    const fechar = () => {
      document.removeEventListener("keydown", fecharComEsc);
      modal.remove();
    };
    const fecharComEsc = (event) => {
      if (event.key === "Escape") fechar();
    };
    modal.querySelector(".loja-produto-fechar")?.addEventListener("click", fechar);
    if (imagensProduto.length > 1) {
      let imagemAtual = 0;
      const imgEl = modal.querySelector("[data-produto-galeria-img]");
      const contadorEl = modal.querySelector("[data-produto-galeria-count]");
      const atualizarGaleria = () => {
        if (!imgEl) return;
        imgEl.src = imagensProduto[imagemAtual];
        imgEl.alt = `${titulo} - imagem ${imagemAtual + 1}`;
        if (contadorEl) contadorEl.textContent = `${imagemAtual + 1}/${imagensProduto.length}`;
      };
      modal.querySelector("[data-produto-galeria-prev]")?.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        imagemAtual = (imagemAtual - 1 + imagensProduto.length) % imagensProduto.length;
        atualizarGaleria();
      });
      modal.querySelector("[data-produto-galeria-next]")?.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        imagemAtual = (imagemAtual + 1) % imagensProduto.length;
        atualizarGaleria();
      });
    }
    modal.addEventListener("click", (event) => {
      if (event.target === modal) fechar();
    });
    document.addEventListener("keydown", fecharComEsc);
    document.body.appendChild(modal);
  }

  if (typeof document !== "undefined" && typeof window !== "undefined" && !window.__lojaProdutoDelegadoBound) {
    window.__lojaProdutoDelegadoBound = true;
    document.addEventListener("click", (event) => {
      const fotoCard = event.target.closest("[data-loja-foto]");
      if (fotoCard && !event.target.closest("a, button")) {
        const item = window.__lojaFotosDetalhes?.[fotoCard.dataset.lojaFoto];
        if (!item?.slug) return;
        event.preventDefault();
        event.stopPropagation();
        abrirModalFotosEstabelecimentoPublico(window.__lojaFotosGrupos?.[item.slug] || {}, item.index || 0);
        return;
      }
      if (event.__lojaProdutoHandled) return;
      const card = event.target.closest("[data-loja-produto]");
      if (!card || event.target.closest("a, button")) return;
      const tipo = card.dataset.lojaProdutoTipo || "produto";
      const key = card.dataset.lojaProdutoKey || `${tipo}:${card.dataset.lojaProduto || ""}`;
      const item = window.__lojaProdutosDetalhes?.[key];
      if (!item) return;
      event.__lojaProdutoHandled = true;
      abrirModalProdutoEstabelecimento(item, tipo === "promocao" ? "Promocao" : "Produto");
    });
  }

  function numeroPrecoPromocao(valor) {
    if (typeof valor === "number") return valor;
    const texto = String(valor || "").replace(/[^\d,.-]/g, "").replace(/\./g, "").replace(",", ".");
    const numero = Number(texto);
    return Number.isFinite(numero) ? numero : 0;
  }

  function descontoPromocao(item) {
    const atual = numeroPrecoPromocao(item?.preco);
    const antigo = numeroPrecoPromocao(item?.precoAntigo);
    if (!atual || !antigo || antigo <= atual) return 0;
    return Math.round(((antigo - atual) / antigo) * 100);
  }

  function promoBadgeClass(item) {
    const texto = String(item?.desconto || item?.valorTexto || item?.preco || "").toLowerCase();
    if (String(item?.destaque || "").toLowerCase().includes("super")) return "super";
    if (texto.includes("%")) return texto.includes("até") || texto.includes("ate") ? "blue" : "purple";
    if (texto.includes("off")) return "pink";
    return "darkblue";
  }

  function promoValorTexto(item, precoFmt = "") {
    const valorTexto = String(item?.valorTexto || "").trim();
    if (valorTexto) return valorTexto.toUpperCase();
    const desconto = String(item?.desconto || "").trim();
    if (desconto) return desconto.toUpperCase();
    if (precoFmt) return `R$ ${String(precoFmt).replace(/^R\$\s*/i, "")}`;
    const pct = descontoPromocao(item);
    return pct ? `${pct}% OFF` : "OFERTA";
  }

  function formatarMoedaPromo(valor) {
    const numero = numeroPrecoPromocao(valor);
    if (!numero) return "";
    return numero.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
  }

  function promoShareData(item = null) {
    const baseUrl = `${location.origin}${location.pathname}#promocoes`;
    if (!item) {
      return {
        title: "Promocoes da cidade",
        text: "Veja as promocoes da cidade no Ola Carlopolis.",
        url: baseUrl
      };
    }
    return {
      title: item.titulo || "Promocao",
      text: `Vi a promocao ${item.titulo || ""} no Ola Carlopolis.`,
      url: `${baseUrl}-${item.estabelecimentoId || "todos"}`
    };
  }

  function escapePromoHtml(value) {
    return String(value ?? "").replace(/[&<>"']/g, (char) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#039;"
    }[char]));
  }

  function boolStr(v) { return v ? "Sim" : "Não"; }
  function m2(v) { return v ? `${v} m²` : "-"; }

  function nomeResponsavel(im) {
    if (im.corretor) return String(im.corretor);
    if (Array.isArray(im.corretores) && im.corretores.length) return String(im.corretores[0]);
    return "";
  }



