  const stateImoveis = { all: [], filtered: [], map: null, markers: [] };

  function normalizarBairroImovelTexto(value = "") {
    return String(value || "")
      .trim()
      .replace(/\s+/g, " ")
      .replace(/^bairro\s+/i, "");
  }

  function extrairBairroImovel(im = {}) {
    const direto = normalizarBairroImovelTexto(im.bairro || im.bairroNome || im.neighborhood || "");
    if (direto) return direto;
    const endereco = normalizarBairroImovelTexto(im.endereco || im.localizacao || im.address || "");
    if (!endereco) return "";
    const partes = endereco.split(/\s[-–—]\s|,|\/|\|/).map(normalizarBairroImovelTexto).filter(Boolean);
    const candidatos = partes.filter((parte) => !/carlopolis|parana|\bpr\b|\d/.test(parte.toLowerCase()));
    return candidatos[0] || partes[0] || "";
  }

  function chaveBairroImovel(value = "") {
    return normalizarBairroImovelTexto(value)
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");
  }

  function nomeCorretorSemRegistro(value = "") {
    return String(value || "")
      .trim()
      .replace(/\bcreci\b\s*[:.-]?\s*/gi, " ")
      .replace(/\s*[-–—]?\s*\d{1,3}(?:[.\s]\d{3})+\s*[-/]?\s*[a-z]?\b/gi, " ")
      .replace(/\s*[-–—]?\s*\d{4,6}\s*[-/]?\s*[a-z]?\b/gi, " ")
      .replace(/\s*[-–—]\s*$/g, "")
      .replace(/\s+/g, " ")
      .trim();
  }

  function chaveCorretorImovel(value = "") {
    return nomeCorretorSemRegistro(value)
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]/g, "");
  }

  function corretoresDoImovel(im = {}) {
    const valores = Array.isArray(im.corretores) && im.corretores.length
      ? im.corretores
      : [im.corretor];
    return valores.map((value) => String(value || "").trim()).filter(Boolean);
  }

  function imovelTemCorretor(im = {}, corretorSelecionado = "") {
    if (!corretorSelecionado) return true;
    return corretoresDoImovel(im).some((nome) => chaveCorretorImovel(nome) === corretorSelecionado);
  }

  function aplicarFiltrosImoveis() {
    const tipo = document.getElementById("imTipo").value;
    const q = parseInt(document.getElementById("imQuartos").value || 0, 10);
    const p = parseInt(document.getElementById("imPreco").value || 0, 10);
    const amen = Array.from(document.querySelectorAll(".amenity-chip.active")).map(c => c.dataset.key);
    const corretorSelecionado = document.getElementById("filtroCorretor")?.value || "";
    const procuraSelecionado = document.getElementById("filtroProcura")?.value || "";
    const bairroSelecionado = document.getElementById("filtroBairroImovel")?.value || "";
    const somenteDisp = document.getElementById("somenteDisponiveis")?.checked || false;
    const ordenacao = document.getElementById("ordenacaoImoveis")?.value || "";

    const isFechado = (st) => {
      if (!st) return false;
      const s = String(st).toLowerCase();
      return s.includes("vendido") || s.includes("alugado") || s.includes("negociado");
    };

    // 1) FILTRAR
    stateImoveis.filtered = stateImoveis.all.filter(im => {
      const tipoOk = !tipo || im.tipo === tipo;
      const qOk = !q || (im.quartos >= q);
      const pOk = !p || (im.valor <= p);

      const corretorOk = imovelTemCorretor(im, corretorSelecionado);

      const procuraOk =
        !procuraSelecionado ||
        (String(im.procura || "").toLowerCase() === procuraSelecionado.toLowerCase());

      const bairroOk =
        !bairroSelecionado ||
        chaveBairroImovel(extrairBairroImovel(im)) === bairroSelecionado;

      let amenOk = true;
      if (amen.includes("piscina")) amenOk = amenOk && !!im.piscina;
      if (amen.includes("churrasqueira")) amenOk = amenOk && !!im.churrasqueira;
      if (amen.includes("vagas")) amenOk = amenOk && (im.vagas >= 2);

      const disponivelOk = !somenteDisp || !isFechado(im.status);

      return tipoOk && qOk && pOk && corretorOk && procuraOk && bairroOk && amenOk && disponivelOk;
    });

    // 2) ORDENAR
    if (ordenacao === "disponiveis") {
      stateImoveis.filtered.sort((a, b) => {
        const A = isFechado(a.status) ? 1 : 0;
        const B = isFechado(b.status) ? 1 : 0;
        if (A !== B) return A - B;
        return 0;
      });
    } else if (ordenacao === "preco_asc") {
      stateImoveis.filtered.sort((a, b) => (a.valor || 0) - (b.valor || 0));
    } else if (ordenacao === "preco_desc") {
      stateImoveis.filtered.sort((a, b) => (b.valor || 0) - (a.valor || 0));
    }

    // 3) ATUALIZA CONTAGEM DOS FILTROS
atualizarContagemFiltroProcura();
popularFiltroCorretor();
popularFiltroBairroImovel();

desenharGridImoveis(stateImoveis.filtered);
plotarPinsImoveis(stateImoveis.filtered);
  }

  function atualizarContagemFiltroProcura() {
  const select = document.getElementById("filtroProcura");
  if (!select) return;

  const selecionadoAtual = select.value;

  const tipo = document.getElementById("imTipo")?.value || "";
  const q = parseInt(document.getElementById("imQuartos")?.value || 0, 10);
  const p = parseInt(document.getElementById("imPreco")?.value || 0, 10);
  const amen = Array.from(document.querySelectorAll(".amenity-chip.active")).map(c => c.dataset.key);
  const corretorSelecionado = document.getElementById("filtroCorretor")?.value || "";
  const bairroSelecionado = document.getElementById("filtroBairroImovel")?.value || "";
  const somenteDisp = document.getElementById("somenteDisponiveis")?.checked || false;

  const isFechado = (st) => {
    if (!st) return false;
    const s = String(st).toLowerCase();
    return s.includes("vendido") || s.includes("alugado") || s.includes("negociado");
  };

  const tipos = [
    { value: "casa", label: "Casa" },
    { value: "chacara", label: "Chacara" },
    { value: "comercial", label: "Comercial" },
    { value: "condominio", label: "Condomínio" },
    { value: "galpao", label: "Galpão" },
    { value: "represa", label: "Represa" },
    { value: "sitio", label: "Sitio" },
    { value: "terreno", label: "Terreno" }
  ];

  const contagem = {};
  tipos.forEach(t => contagem[t.value] = 0);

  // Conta usando TODOS os imóveis filtrados pelos outros filtros,
  // mas IGNORANDO o filtroProcura atual
  const baseParaContagem = stateImoveis.all.filter(im => {
    const tipoOk = !tipo || im.tipo === tipo;
    const qOk = !q || (im.quartos >= q);
    const pOk = !p || (im.valor <= p);

    const corretorOk = imovelTemCorretor(im, corretorSelecionado);

    const bairroOk =
      !bairroSelecionado ||
      chaveBairroImovel(extrairBairroImovel(im)) === bairroSelecionado;

    let amenOk = true;
    if (amen.includes("piscina")) amenOk = amenOk && !!im.piscina;
    if (amen.includes("churrasqueira")) amenOk = amenOk && !!im.churrasqueira;
    if (amen.includes("vagas")) amenOk = amenOk && (im.vagas >= 2);

    const disponivelOk = !somenteDisp || !isFechado(im.status);

    return tipoOk && qOk && pOk && corretorOk && bairroOk && amenOk && disponivelOk;
  });

  baseParaContagem.forEach(im => {
    const tipoProcura = String(im.procura || "").toLowerCase();
    if (contagem.hasOwnProperty(tipoProcura)) {
      contagem[tipoProcura]++;
    }
  });

  select.innerHTML = `<option value="">Todos (${baseParaContagem.length})</option>`;

  tipos.forEach(t => {
    const option = document.createElement("option");
    option.value = t.value;
    option.textContent = `${t.label} (${contagem[t.value] || 0})`;
    if (selecionadoAtual === t.value) option.selected = true;
    select.appendChild(option);
  });
}




  function desenharGridImoveis(lista) {
    const el = document.getElementById("imGrid");
    if (!lista.length) {
      el.innerHTML = `<p style="text-align:center">Nenhum imóvel encontrado.</p>`;
      return;
    }
    el.innerHTML = lista.map(im => cardImovelHTML(im)).join("");

    // inicia swipers compactos por card
    setTimeout(() => {
      document.querySelectorAll(".swiper-imovel-mini").forEach((box) => {
        new Swiper(box, { loop: true, autoplay: { delay: 4000 } });
      });
    }, 0);

    // conecta botões
    el.querySelectorAll(".card-imovel").forEach((card) => {
      card.addEventListener("click", (ev) => {
        if (ev.__imovelDetalhesHandled) return;
        if (ev.target.closest("button, a, input, select, textarea, [data-imovel-detalhes]")) return;
        const im = stateImoveis.all.find((item) => item.id === card.dataset.id);
        if (im) {
          registrarCliqueImovel("visualizacao", im);
          const cardsAtivos = Boolean(
            window.__imoveisModoCards
            || document.getElementById("imModoCards")?.checked
            || document.querySelector(".imoveis-wrap")?.classList.contains("im-cards-mode")
          );
          if (cardsAtivos) {
            ev.__imovelDetalhesHandled = true;
            abrirModalDetalhesImovel(im);
          } else if (typeof focarNoMapa === "function") {
            focarNoMapa(im.id);
          }
        }
      });
    });

    if (el.dataset.imovelDetalhesDelegado !== "1") {
      el.dataset.imovelDetalhesDelegado = "1";
      const abrirDetalhes = (ev) => {
        if (ev.__imovelDetalhesHandled) return;
        const titulo = ev.target.closest?.("[data-imovel-detalhes]");
        if (!titulo || !el.contains(titulo)) return;
        const cardsAtivos = Boolean(
          window.__imoveisModoCards
          || document.getElementById("imModoCards")?.checked
          || document.querySelector(".imoveis-wrap")?.classList.contains("im-cards-mode")
        );
        if (!cardsAtivos) return;
        ev.preventDefault();
        ev.stopPropagation();
        const im = stateImoveis.all.find((item) => item.id === titulo.getAttribute("data-imovel-detalhes"));
        if (!im) return;
        ev.__imovelDetalhesHandled = true;
        registrarCliqueImovel("visualizacao", im).catch(() => { });
        abrirModalDetalhesImovel(im);
      };
      el.addEventListener("click", abrirDetalhes);
      el.addEventListener("keydown", (ev) => {
        if (ev.key === "Enter" || ev.key === " ") abrirDetalhes(ev);
      });
    }

    // [FOTOS] – abre a galeria E registra clique "fotos"
    // permitir abrir a galeria clicando na imagem ou no botão de lupa
    el.querySelectorAll(".card-imovel .swiper-imovel-mini img, .card-imovel .zoom-thumb").forEach(node => {
      node.addEventListener("click", (ev) => {
        ev.stopPropagation();
        const card = ev.currentTarget.closest(".card-imovel");
        const id = card?.getAttribute("data-id") || ev.currentTarget.getAttribute("data-id");
        if (!id) return;
        const im = stateImoveis.all.find(x => x.id === id);
        if (im) {
          registrarCliqueImovel('fotos', im);   // <<< ADICIONE ESTA LINHA
          abrirModalImoveis(im, ev.currentTarget.currentSrc || ev.currentTarget.src);
        }
      });
    });




    // WhatsApp – abrir aba imediatamente; registrar em paralelo
    function abrirModalContatoImovel(im) {
      const nomeSalvo = localStorage.getItem("visitante_nome");

      // ✅ Se já existir nome salvo, pula a modal e envia direto
      if (nomeSalvo) {
        enviarWhatsAppImovel(im, nomeSalvo);
        return;
      }

      // remove modais anteriores
      document.querySelectorAll(".im-contato-modal").forEach(m => m.remove());

      const modal = document.createElement("div");
      modal.className = "im-contato-modal";
      modal.innerHTML = `
    <div class="im-contato-box" role="dialog" aria-modal="true">
      <button class="im-contato-close" title="Fechar">&times;</button>
      <h3>Antes de falar no WhatsApp</h3>
      <p>Digite seu nome para eu me apresentar ao corretor:</p>
      <input type="hidden" id="imResponsavel" value="${getResponsavelImovel(im)}"> <!-- NOVO -->
      <label class="im-contato-label" for="imContatoNome">Seu nome</label>
      <input id="imContatoNome" class="im-contato-input" type="text" placeholder="Ex.: Maria Silva" maxlength="40">
      <div class="im-contato-actions">
        <button class="im-contato-cancel">Cancelar</button>
        <button class="im-contato-send">
          <i class="fa-brands fa-whatsapp"></i> Enviar no WhatsApp
        </button>
      </div>
    </div>
  `;
      document.body.appendChild(modal);

      const input = modal.querySelector("#imContatoNome");
      setTimeout(() => input.focus(), 50);

      function fechar() { modal.remove(); }
      modal.addEventListener("click", (e) => { if (e.target === modal) fechar(); });
      modal.querySelector(".im-contato-close").addEventListener("click", fechar);
      modal.querySelector(".im-contato-cancel").addEventListener("click", fechar);

      // botão enviar
      modal.querySelector(".im-contato-send").addEventListener("click", () => {
        let nome = (input.value || "").trim();
        if (!nome) {
          input.focus();
          input.classList.add("im-contato-input--err");
          setTimeout(() => input.classList.remove("im-contato-input--err"), 600);
          return;
        }

        localStorage.setItem("visitante_nome", nome);
        enviarWhatsAppImovel(im, nome);
        fechar();
      });
    }

    // --- Função para abrir WhatsApp com saudação e salvar no Firebase ---
    function enviarWhatsAppImovel(im, nome) {
      const numero = somenteDigitos(im.telefone || "");

      // Saudação (sem “Encontrei seu número no Olá Carlópolis”)
      let saudacao = (typeof gerarMensagemWhatsApp === "function")
        ? (gerarMensagemWhatsApp().trim() || "Olá!")
        : "Olá!";
      saudacao = saudacao.replace(/Encontrei seu numero no Ola Carlopolis\.?/i, "")
        .replace(/Encontrei seu número no Olá Carlópolis\.?/i, "")
        .trim();

      const codigo = im.codRef ? im.codRef : (im.id ? im.id.toUpperCase() : "N/D");
      const msg = `${saudacao ? saudacao + " " : ""}Meu nome é ${nome}. Vi o imóvel "${im.titulo}", cod de ref: ( ${codigo} ) no Olá Carlópolis e gostaria de mais informações.`;
      const url = `https://wa.me/55${numero}?text=${encodeURIComponent(msg)}`;

      try {
        // O clique do botao ja foi contabilizado antes desta etapa.
        // Aqui e salva somente a confirmacao com o nome informado.
        salvarContatoImovel(im, nome);

        if (typeof logEventoCliqueImovel === "function") {
          logEventoCliqueImovel("whatsapp", im);
        }
      } catch (e) { }

      // abre o WhatsApp (gesto do usuário)
      window.open(url, "_blank");
    }

    function salvarContatoImovel(im, nome) {
      try {
        if (!window.firebase || !firebase.database) return;
        const hoje = new Date().toISOString().slice(0, 10);
        const ref = firebase.database()
          .ref(`imoveis/contatos/${hoje}/${im.id}`)
          .push();

        ref.set({
          nome: String(nome || "").slice(0, 80),
          imovelId: im.id,
          imovelTitulo: im.titulo || "",
          destinoFone: somenteDigitos(im.telefone || ""),
          corretor: (typeof getCorretorPrincipal === "function" ? getCorretorPrincipal(im) : (im.corretor || "")) || "",
          responsavel: getResponsavelImovel(im), // <-- NOVO: sempre preenche
          pagina: location.href,
          userAgent: navigator.userAgent,
          ts: firebase.database.ServerValue.TIMESTAMP
        }).catch(() => { });
      } catch (e) { }
    }




    // --- Conecta os botões "Falar no WhatsApp" (um único listener por botão)
    el.querySelectorAll("[data-action='whats']").forEach(btn => {
      if (btn.dataset.bindWhats === "1") return; // evita rebind
      btn.dataset.bindWhats = "1";

      btn.addEventListener("click", (ev) => {
        ev.preventDefault();
        const id = ev.currentTarget.getAttribute("data-id");
        const im = stateImoveis.all.find(x => x.id === id);
        if (!im) return;
        registrarCliqueImovel("whatsapp", im).catch(() => { });
        abrirModalContatoImovel(im);
      });
    });

    el.querySelectorAll("[data-action='instagram']").forEach((link) => {
      link.addEventListener("click", () => {
        const im = stateImoveis.all.find((item) => item.id === link.getAttribute("data-id"));
        if (im) registrarCliqueImovel("instagram", im).catch(() => { });
      });
    });









    // permitir abrir a galeria clicando na imagem ou no botão de lupa
    el.querySelectorAll(".card-imovel .swiper-imovel-mini img, .card-imovel .zoom-thumb").forEach(node => {
      node.addEventListener("click", (ev) => {
        ev.stopPropagation(); // evita acionar o click do card (mapa)
        const card = ev.currentTarget.closest(".card-imovel");
        const id = card?.getAttribute("data-id") || ev.currentTarget.getAttribute("data-id");
        if (!id) return;
        const im = stateImoveis.all.find(x => x.id === id);
        if (im) abrirModalImoveis(im, ev.currentTarget.currentSrc || ev.currentTarget.src);
      });
    });

  } function isTerreno(im) {
    const t = String(im.procura || im.tipoImovel || im.categoria || "").toLowerCase();
    const noTitulo = String(im.titulo || "").toLowerCase().includes("terreno");
    return t === "terreno" || noTitulo;
  }
  function hasNum(v) { return Number.isFinite(Number(v)) && Number(v) > 0; }

  function renderChips(im) {
    const terr = isTerreno(im);
    const chips = [];

    // Para casas/apês (não mostra em terreno se não fizer sentido)
    if (!terr && hasNum(im.quartos)) chips.push(`<div class="spec-chip"><span class="k">Quartos</span><span class="v">${im.quartos}</span></div>`);
    if (!terr && im.suite) chips.push(`<div class="spec-chip chip-mini"><span class="k">Suíte</span><span class="v">${im.suite}</span></div>`);
    if (!terr && hasNum(im.banheiros)) chips.push(`<div class="spec-chip"><span class="k">Banheiros</span><span class="v">${im.banheiros}</span></div>`);
    if (!terr && hasNum(im.vagas)) chips.push(`<div class="spec-chip"><span class="k">Vagas</span><span class="v">${im.vagas}</span></div>`);
    if (!terr && hasNum(im.salas)) chips.push(`<div class="spec-chip"><span class="k">Salas</span><span class="v">${im.salas}</span></div>`);
    if (!terr && hasNum(im.cozinhas)) chips.push(`<div class="spec-chip"><span class="k">Cozinhas</span><span class="v">${im.cozinhas}</span></div>`);
    if (!terr && im.churrasqueira) chips.push(`<div class="spec-chip"><span class="k">Churrasqueira</span><span class="v">${im.churrasqueira}</span></div>`);
    if (!terr && im.piscina) chips.push(`<div class="spec-chip"><span class="k">Piscina</span><span class="v">${im.piscina}</span></div>`);
    if (!terr && im.quintal) chips.push(`<div class="spec-chip chip-mini"><span class="k">Quintal</span><span class="v">${im.quintal}</span></div>`);

    if (!terr && im.escritorio) chips.push(`<div class="spec-chip chip-mini"><span class="k">Escritorio</span><span class="v">${im.escritorio}</span></div>`);
    if (!terr && im.outros) chips.push(`<div class="spec-chip chip-mini"><span class="k">Outros</span><span class="v">${im.outros}</span></div>`);


    // Área (aceita TEXTO ou NÚMERO)
    if (im.area !== undefined && im.area !== null && String(im.area).trim() !== "") {
      const areaStr = hasNum(im.area) ? `${Number(im.area)} m²` : String(im.area);
      chips.push(
        `<div class="spec-chip"><span class="k">Área</span><span class="v">${areaStr} </span></div>`
      );
    }



    // Construção (normalmente não para terreno)
    if (!terr && hasNum(im.construcao)) chips.push(`<div class="spec-chip"><span class="k">Construção</span><span class="v">${Number(im.construcao)} m²</span></div>`);

    return chips.join("");
  }

  function instagramResponsavelImovel(im = {}) {
    const direto = String(im.instagram || im.Instagram || im.linkInstagram || "").trim();
    if (direto) return direto;

    const chaves = [
      im.clienteId,
      im.clienteNome,
      im.corretor,
      ...(Array.isArray(im.corretores) ? im.corretores : [])
    ].map((value) => normalizeName(value || "")).filter(Boolean);

    for (const categoria of categories || []) {
      const estabelecimento = (categoria.establishments || []).find((item) => {
        const aliases = [
          item.nomeNormalizado,
          item.name,
          item.nome,
          item.id
        ].map((value) => normalizeName(value || "")).filter(Boolean);
        return chaves.some((chave) => aliases.some((alias) => (
          chave === alias
          || (chave.length > 4 && alias.length > 4 && (chave.includes(alias) || alias.includes(chave)))
        )));
      });
      if (estabelecimento?.instagram) return estabelecimento.instagram;
    }
    return "";
  }

  function abrirModalDetalhesImovel(im = {}) {
    document.querySelector(".imovel-detalhes-modal")?.remove();
    const responsavel = nomeResponsavel(im);
    const responsavelSlug = normalizeName(im.estabelecimentoId || im.clienteId || im.clienteNome || responsavel || "");
    const valor = Number(im.valor || 0);
    const valorFormatado = valor
      ? valor.toLocaleString("pt-BR", { style: "currency", currency: "BRL" }) + (im.tipo === "aluguel" ? " / mes" : "")
      : "Consulte";
    const detalhes = [
      ["Tipo do imovel", im.procura || im.tipoImovel || im.categoria],
      ["Quartos", im.quartos],
      ["Suites", im.suite],
      ["Banheiros", im.banheiros],
      ["Vagas", im.vagas],
      ["Salas", im.salas],
      ["Cozinhas", im.cozinhas],
      ["Area", im.area ? `${im.area}${String(im.area).includes("m") ? "" : " m²"}` : ""],
      ["Construcao", im.construcao ? `${im.construcao}${String(im.construcao).includes("m") ? "" : " m²"}` : ""],
      ["Piscina", im.piscina],
      ["Churrasqueira", im.churrasqueira],
      ["Quintal", im.quintal],
      ["Escritorio", im.escritorio],
      ["Outros", im.outros],
      ["Corretor", responsavel]
    ].filter(([, value]) => value !== undefined && value !== null && String(value).trim() !== "" && String(value) !== "0");
    const imagens = Array.isArray(im.imagens) ? im.imagens.filter(Boolean) : (im.imagem ? [im.imagem] : []);

    const modal = document.createElement("div");
    modal.className = "imovel-detalhes-modal";
    modal.innerHTML = `
      <section class="imovel-detalhes-dialog" role="dialog" aria-modal="true" aria-label="Detalhes de ${escapePromoHtml(im.titulo || "imovel")}">
        <button type="button" class="imovel-detalhes-fechar" aria-label="Fechar detalhes" title="Fechar">&times;</button>
        <div class="imovel-detalhes-media">
          <span class="imovel-detalhes-finalidade">${escapePromoHtml(String(im.tipo || "Imovel").toUpperCase())}</span>
          ${imagens[0] ? `
            <div class="imovel-detalhes-galeria-track" data-imovel-galeria-track>
              ${imagens.map((src, index) => `<img src="${escapePromoHtml(src)}" alt="Foto ${index + 1} de ${escapePromoHtml(im.titulo || "Imovel")}" loading="lazy" decoding="async">`).join("")}
            </div>
            ${imagens.length > 1 ? `
              <button type="button" class="imovel-detalhes-galeria-nav anterior" data-imovel-galeria-anterior aria-label="Foto anterior"><i class="fa-solid fa-chevron-left"></i></button>
              <button type="button" class="imovel-detalhes-galeria-nav proxima" data-imovel-galeria-proxima aria-label="Proxima foto"><i class="fa-solid fa-chevron-right"></i></button>
              <span class="imovel-detalhes-galeria-contador" data-imovel-galeria-contador>1 / ${imagens.length}</span>
            ` : ""}
          ` : `<div class="imovel-detalhes-sem-foto"><i class="fa-solid fa-house"></i></div>`}
        </div>
        <div class="imovel-detalhes-conteudo">
          <div class="imovel-detalhes-topo">
            <div>
              <h2>${escapePromoHtml(im.titulo || "Imovel")}</h2>
              ${im.endereco ? `<p class="imovel-detalhes-endereco"><i class="fa-solid fa-location-dot"></i><span>${escapePromoHtml(im.endereco)}</span></p>` : ""}
              ${responsavel ? `<p class="imovel-detalhes-endereco"><i class="fa-solid fa-user-tie"></i><a href="#${escapePromoHtml(responsavelSlug)}" data-public-client-link="${escapePromoHtml(responsavelSlug)}">${escapePromoHtml(responsavel)}</a></p>` : ""}
            </div>
            <div class="imovel-detalhes-financeiro">
              <strong class="imovel-detalhes-valor">${escapePromoHtml(valorFormatado)}</strong>
              <span class="imovel-detalhes-referencia"><i class="fa-solid fa-hashtag"></i> Ref.: ${escapePromoHtml(String(im.codRef || im.id || "").toUpperCase())}</span>
            </div>
          </div>
          ${im.descricao ? `
            <section class="imovel-detalhes-descricao">
              <div class="imovel-detalhes-descricao-titulo"><i class="fa-solid fa-align-left"></i><span>Sobre o imóvel</span></div>
              <p>${escapePromoHtml(im.descricao)}</p>
            </section>
          ` : ""}
          <div class="imovel-detalhes-grade">
            ${detalhes.map(([label, value]) => `
              <div><span>${escapePromoHtml(label)}</span><strong>${escapePromoHtml(value)}</strong></div>
            `).join("")}
          </div>
        </div>
      </section>
    `;
    document.body.appendChild(modal);

    const fechar = () => {
      document.removeEventListener("keydown", fecharComEsc);
      modal.remove();
    };
    let indiceImagem = 0;
    const galeriaTrack = modal.querySelector("[data-imovel-galeria-track]");
    const contadorGaleria = modal.querySelector("[data-imovel-galeria-contador]");
    const atualizarGaleria = (novoIndice) => {
      if (!galeriaTrack || !imagens.length) return;
      indiceImagem = (novoIndice + imagens.length) % imagens.length;
      galeriaTrack.style.transform = `translateX(-${indiceImagem * 100}%)`;
      if (contadorGaleria) contadorGaleria.textContent = `${indiceImagem + 1} / ${imagens.length}`;
    };
    const navegarGaleria = (direcao) => {
      registrarCliqueImovel("fotos", im).catch(() => { });
      atualizarGaleria(indiceImagem + direcao);
    };
    let toqueInicioX = 0;
    let toqueInicioY = 0;
    let galeriaFoiArrastada = false;
    const fecharComEsc = (event) => {
      if (event.key === "Escape") fechar();
      if (event.key === "ArrowLeft" && imagens.length > 1) navegarGaleria(-1);
      if (event.key === "ArrowRight" && imagens.length > 1) navegarGaleria(1);
    };
    modal.querySelector(".imovel-detalhes-fechar")?.addEventListener("click", fechar);
    modal.addEventListener("click", (event) => {
      if (event.target === modal) fechar();
    });
    modal.querySelector("[data-imovel-galeria-anterior]")?.addEventListener("click", () => navegarGaleria(-1));
    modal.querySelector("[data-imovel-galeria-proxima]")?.addEventListener("click", () => navegarGaleria(1));
    galeriaTrack?.addEventListener("touchstart", (event) => {
      const toque = event.changedTouches?.[0];
      if (!toque) return;
      toqueInicioX = toque.clientX;
      toqueInicioY = toque.clientY;
      galeriaFoiArrastada = false;
    }, { passive: true });
    galeriaTrack?.addEventListener("touchend", (event) => {
      const toque = event.changedTouches?.[0];
      if (!toque || imagens.length < 2) return;
      const diferencaX = toque.clientX - toqueInicioX;
      const diferencaY = toque.clientY - toqueInicioY;
      if (Math.abs(diferencaX) < 45 || Math.abs(diferencaX) <= Math.abs(diferencaY)) return;
      galeriaFoiArrastada = true;
      navegarGaleria(diferencaX < 0 ? 1 : -1);
    }, { passive: true });
    galeriaTrack?.addEventListener("click", () => {
      if (galeriaFoiArrastada) {
        galeriaFoiArrastada = false;
        return;
      }
      registrarCliqueImovel("fotos", im).catch(() => { });
      fechar();
      abrirModalImoveis(im, imagens[indiceImagem] || imagens[0] || "");
    });
    document.addEventListener("keydown", fecharComEsc);
    modal.querySelector(".imovel-detalhes-fechar")?.focus();
  }


