  function textoSeguroAutomoveis(valor) {
    return String(valor || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function automovelDeRegistro(item, key) {
    return {
      id: key || item.id || "",
      tipo: item.Tipo || item.tipo || item.categoria || "",
      marca: item.Marca || item.marca || "",
      modelo: item.Modelo || item.modelo || item.titulo || item.Titulo || "",
      ano: item.Ano || item.ano || "",
      createdAt: item.createdAt || item.criadoEm || item.dataCriacao || "",
      updatedAt: item.updatedAt || item.dataAtualizacao || item.atualizadoEm || "",
      codRef: item.codRef || item.codigo || item.Codigo || item["Codigo Referencia"] || item["Código Referencia"] || item["Cod Ref"] || key || "",
      preco: item.Preco || item.Preço || item.preco || item.valor || "",
      condicao: item.Condicao || item.condicao || item.estado || "",
      km: item.Km || item.km || item.quilometragem || "",
      imagem: item.Link_Imagem || item["Imagem URL"] || item.imagem || item.image || "",
      imagens: imagensAutomovelPublico(item),
      descricao: item.Descricao || item.Descrição || item.descricao || "",
      contato: item.Contato || item.contato || item.whatsapp || "",
      vendedor: item.Vendedor || item.vendedor || item.loja || item.nomeLoja || item.lojaNome || item.empresa || item.clienteNome || item.cliente || item.anunciante || item.nomeVendedor || "",
      loja: item.Loja || item.loja || item.nomeLoja || item.lojaNome || item.empresa || item.clienteNome || item.cliente || item.anunciante || item.vendedor || "",
      lojaNome: item.lojaNome || item.nomeLoja || item.LojaNome || item.NomeLoja || "",
      nomeLoja: item.nomeLoja || item.lojaNome || item.NomeLoja || item.LojaNome || "",
      empresa: item.empresa || item.Empresa || "",
      anunciante: item.anunciante || item.Anunciante || "",
      clienteId: item.clienteId || item.ClienteId || item.ClienteID || item.idCliente || item.cliente_id || item.cliente || "",
      idCliente: item.idCliente || item.ClienteId || item.ClienteID || item.clienteId || item.cliente_id || "",
      clienteSlug: item.clienteSlug || item.slugCliente || item.cliente_slug || "",
      clienteNome: item.clienteNome || item.ClienteNome || item.nomeCliente || item.NomeCliente || "",
      nomeCliente: item.nomeCliente || item.NomeCliente || item.clienteNome || item.ClienteNome || "",
      estabelecimentoId: item.estabelecimentoId || item.EstabelecimentoId || item.estabelecimentoID || item.estabelecimento || item.estabelecimentoSlug || "",
      estabelecimentoNome: item.estabelecimentoNome || item.nomeEstabelecimento || item.EstabelecimentoNome || item.estabelecimento || "",
      nomeEstabelecimento: item.nomeEstabelecimento || item.estabelecimentoNome || item.EstabelecimentoNome || item.estabelecimento || "",
      raw: item,
      instagram: item.Instagram || item.instagram || item.linkInstagram || "",
      combustivel: item.Combustivel || item.combustivel || "",
      cambio: item.Cambio || item.cambio || "",
      cor: item.Cor || item.cor || "",
      consumoMedio: item.consumoMedio || item.ConsumoMedio || item["Consumo Medio"] || item["Consumo Médio"] || "",
      aceitaTroca: item.aceitaTroca || item.AceitaTroca || item["Aceita Troca"] || "",
      aceitaFinanciamento: item.aceitaFinanciamento || item.AceitaFinanciamento || item["Aceita Financiamento"] || "",
      documentacao: item.documentacao || item.Documentacao || item["Documentação"] || "",
      motor: item.motor || item.Motor || "",
      direcao: item.direcao || item.Direcao || item["Direção"] || "",
      vidroEletrico: item.vidroEletrico || item.VidroEletrico || item["Vidro Eletrico"] || item["Vidro Elétrico"] || "",
      travaEletrica: item.travaEletrica || item.TravaEletrica || item["Trava Eletrica"] || item["Trava Elétrica"] || "",
      portas: item.portas || item.Portas || "",
      freioAbs: item.freioAbs || item.FreioAbs || item["Freio ABS"] || "",
      cilindrada: item.cilindrada || item.Cilindrada || "",
      partida: item.partida || item.Partida || "",
      freio: item.freio || item.Freio || "",
      injecaoEletronica: item.injecaoEletronica || item.InjecaoEletronica || item["Injecao Eletronica"] || item["Injeção Eletrônica"] || "",
      cidade: item.Cidade || item.cidade || item.local || "",
      acessorios: item.acessorios || item.Acessorios || item["Acessórios"] || "",
      opcionais: item.Opcionais || item.opcionais || "",
      status: item.status || "ativo",
      ativo: item.ativo === false ? false : true
    };
  }

  function resolverDestinoPublicoAutomovel(item = {}) {
    const candidatos = [
      item.clienteId,
      item.idCliente,
      item.clienteSlug,
      item.clienteNome,
      item.nomeCliente,
      item.estabelecimentoId,
      item.estabelecimentoNome,
      item.nomeEstabelecimento,
      item.lojaNome,
      item.nomeLoja,
      item.loja,
      item.vendedor,
      item.empresa,
      item.anunciante,
      item.raw?.clienteId,
      item.raw?.idCliente,
      item.raw?.clienteSlug,
      item.raw?.clienteNome,
      item.raw?.nomeCliente,
      item.raw?.estabelecimentoId,
      item.raw?.estabelecimento,
      item.raw?.loja,
      item.raw?.vendedor
    ].map(normalizeName).filter(Boolean);
    const direto = candidatos.find((chave) => encontrarCategoriaEstabelecimentoPublico(chave));
    return direto || candidatos[0] || "";
  }

  function renderImoveisCardsEstabelecimento(lista = [], box) {
    if (!box) return;
    const encontrarImovel = (identificador) => {
      const alvo = String(identificador || "").trim().toLowerCase();
      if (!alvo) return null;
      return lista.find((item) => [item.id, item.codRef, item.codigo]
        .some((valor) => String(valor || "").trim().toLowerCase() === alvo)) || null;
    };
    box.innerHTML = lista.length
      ? lista.map((im) => cardImovelHTML(im)).join("")
      : `<p class="list-meta">Nenhum imovel cadastrado para este estabelecimento.</p>`;
    setTimeout(() => {
      box.querySelectorAll(".swiper-imovel-mini").forEach((swiperBox) => {
        if (!swiperBox.swiper) new Swiper(swiperBox, { loop: true, autoplay: { delay: 4000 } });
      });
    }, 0);
    box.querySelectorAll(".card-imovel").forEach((card) => {
      card.addEventListener("click", (ev) => {
        if (ev.__imovelDetalhesHandled) return;
        if (ev.target.closest("button, a, input, select, textarea, [data-imovel-detalhes]")) return;
        const im = encontrarImovel(card.dataset.id);
        if (!im) return;
        ev.__imovelDetalhesHandled = true;
        registrarCliqueImovel("visualizacao", im).catch(() => { });
        abrirModalDetalhesImovel(im);
      });
    });
    box.addEventListener("click", (ev) => {
      if (ev.__imovelDetalhesHandled) return;
      const titulo = ev.target.closest?.("[data-imovel-detalhes]");
      if (titulo && box.contains(titulo)) {
        ev.preventDefault();
        ev.stopPropagation();
        const im = encontrarImovel(titulo.getAttribute("data-imovel-detalhes"));
        if (!im) return;
        ev.__imovelDetalhesHandled = true;
        registrarCliqueImovel("visualizacao", im).catch(() => { });
        abrirModalDetalhesImovel(im);
        return;
      }
      const zoom = ev.target.closest?.(".card-imovel .swiper-imovel-mini img, .card-imovel .zoom-thumb");
      if (zoom && box.contains(zoom)) {
        ev.preventDefault();
        ev.stopPropagation();
        const card = zoom.closest(".card-imovel");
        const id = card?.getAttribute("data-id") || zoom.getAttribute("data-id");
        const im = encontrarImovel(id);
        if (!im) return;
        registrarCliqueImovel("fotos", im).catch(() => { });
        abrirModalImoveis(im, zoom.currentSrc || zoom.src || "");
      }
    });
    box.addEventListener("keydown", (ev) => {
      if (ev.__imovelDetalhesHandled) return;
      if (!["Enter", " "].includes(ev.key)) return;
      const titulo = ev.target.closest?.("[data-imovel-detalhes]");
      if (!titulo || !box.contains(titulo)) return;
      ev.preventDefault();
      const im = encontrarImovel(titulo.getAttribute("data-imovel-detalhes"));
      if (!im) return;
      ev.__imovelDetalhesHandled = true;
      registrarCliqueImovel("visualizacao", im).catch(() => { });
      abrirModalDetalhesImovel(im);
    });
  }

  function normalizarTextoAutomoveis(valor) {
    return String(valor || "").normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
  }

  function numeroAutomoveis(valor) {
    const texto = String(valor || "").replace(/\./g, "").replace(",", ".");
    const match = texto.match(/\d+(\.\d+)?/);
    return match ? Number(match[0]) : 0;
  }

  function formatarPrecoAutomoveis(valor) {
    const texto = String(valor || "").trim();
    if (!texto) return "";
    if (/^consulte$/i.test(texto)) return "Consulte";
    const numero = numeroAutomoveis(valor);
    if (!numero) return texto;
    return numero.toLocaleString("pt-BR", {
      style: "currency",
      currency: "BRL",
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });
  }

  function imagensAutomovelPublico(item) {
    const valores = [];
    const adicionar = (valor) => {
      if (!valor) return;
      if (Array.isArray(valor)) {
        valor.forEach(adicionar);
        return;
      }
      if (typeof valor === "object") {
        adicionar(valor.url || valor.src || valor.imagem || valor.image || valor.link);
        return;
      }
      const texto = String(valor || "").trim();
      if (texto) valores.push(texto);
    };

    adicionar(item.Link_Imagem || item["Imagem URL"] || item.imagem || item.image);
    adicionar(item.imagens || item.Imagens || item.images || item.fotos || item.Fotos);
    return [...new Set(valores)];
  }

  function opcoesAutomoveis(lista, campo) {
    const valores = [...new Set(lista.map((item) => String(item[campo] || "").trim()).filter(Boolean))];
    return valores.sort((a, b) => a.localeCompare(b, "pt-BR")).map((valor) => `<option value="${textoSeguroAutomoveis(valor)}">${textoSeguroAutomoveis(valor)}</option>`).join("");
  }

  function renderAutomoveisCards(lista, box) {
    if (!lista.length) {
      box.innerHTML = `<div class="list-meta">Nenhum automovel encontrado com esses filtros.</div>`;
      return;
    }
    if (typeof window !== "undefined") {
      window.__automoveisDetalhesById = window.__automoveisDetalhesById || {};
      lista.forEach((item) => {
        if (item?.id) window.__automoveisDetalhesById[String(item.id)] = item;
      });
    }

    box.innerHTML = lista.map((item) => {
      const titulo = [item.marca, item.modelo].filter(Boolean).join(" ") || "Automovel";
      const imagens = imagensAutomovelPublico(item);
      const imagemPrincipal = imagens[0] || item.imagem || "";
      const imagensJson = textoSeguroAutomoveis(encodeURIComponent(JSON.stringify(imagens)));
      const contato = String(item.contato || "").replace(/\D/g, "");
      const instagram = String(item.instagram || "").trim();
      const instagramUrl = instagram && instagram.startsWith("http") ? instagram : (instagram ? `https://instagram.com/${instagram.replace(/^@/, "")}` : "");
      const codigoReferencia = String(item.codRef || item.codigo || item.id || `${item.marca}-${item.modelo}-${item.ano}`).replace(/[^a-z0-9_-]/gi, "").slice(0, 18).toUpperCase();
      const detalhesTabela = [
        ["Tipo", item.tipo],
        ["Condicao", item.condicao],
        ["Ano", item.ano],
        ["KM", item.km],
        ["Cambio", item.cambio],
        ["Combustivel", item.combustivel],
        ["Cor", item.cor],
        ["Cidade", item.cidade]
      ].filter(([, valor]) => valor);
      const vendedor = item.vendedor || item.loja || "";
      const precoCard = formatarPrecoAutomoveis(item.preco) || "Consulte";
      const sellerSlug = resolverDestinoPublicoAutomovel(item);
      const whatsappTexto = [
        "Ola! Vi este automovel no Ola Carlopolis e quero mais informacoes.",
        `Referencia: ${codigoReferencia}`,
        `Produto: ${titulo}`,
        `Valor: ${precoCard}`,
        vendedor ? `Loja/Vendedor: ${vendedor}` : "",
        imagemPrincipal ? `Imagem: ${imagemPrincipal}` : ""
      ].filter(Boolean).join("\n");
      return `
        <article id="${novidadeDomId("veiculo", item.id)}" class="auto-card ${item.status === "vendido" ? "is-sold" : ""}"
          data-auto-id="${textoSeguroAutomoveis(item.id || "")}"
          data-novidade-destino="veiculo-${textoSeguroAutomoveis(item.id || "")}">
          <div class="auto-card-media" data-auto-gallery="${imagensJson}" data-auto-title="${textoSeguroAutomoveis(titulo)}">
            ${imagens.length ? `
              <div class="auto-gallery-track">
                <img class="auto-card-img auto-gallery-img" src="${textoSeguroAutomoveis(imagens[0])}" alt="${textoSeguroAutomoveis(titulo)}" data-auto-gallery-index="0" loading="lazy" decoding="async" fetchpriority="low">
              </div>
            ` : `<div class="auto-card-img auto-card-img-empty"><i class="fa-solid fa-car-side"></i></div>`}
            <strong class="auto-price">${textoSeguroAutomoveis(precoCard)}</strong>
            ${item.status === "vendido" ? `<span class="auto-status auto-status-media">Vendido</span>` : ""}
          </div>
          <div class="im-card-body">
            <div class="auto-card-top">
              <div>
                <h3>
                  <span class="auto-title-button" data-auto-detalhes="${textoSeguroAutomoveis(item.id || "")}" role="button" tabindex="0" title="Ver detalhes do veiculo">${textoSeguroAutomoveis(titulo)}</span>
                </h3>
              </div>
            </div>
            <p class="auto-seller"><span>Loja/Vendedor</span><strong>${sellerSlug ? `<a class="auto-seller-link" href="#${textoSeguroAutomoveis(sellerSlug)}" data-public-client-link="${textoSeguroAutomoveis(sellerSlug)}">${textoSeguroAutomoveis(vendedor || item.clienteNome || "Nao informado")}</a>` : textoSeguroAutomoveis(vendedor || "Nao informado")}</strong>${instagramUrl ? `<a class="auto-instagram-icon" target="_blank" href="${textoSeguroAutomoveis(instagramUrl)}" aria-label="Instagram de ${textoSeguroAutomoveis(vendedor || titulo)}"><i class="fa-brands fa-instagram"></i></a>` : ""}</p>
            ${detalhesTabela.length ? `<div class="auto-spec-table">${detalhesTabela.map(([label, valor]) => `<div><span>${textoSeguroAutomoveis(label)}</span><strong>${textoSeguroAutomoveis(valor)}</strong></div>`).join("")}</div>` : ""}
            ${item.opcionais ? `<p class="auto-info-line"><span>Opcionais</span><strong>${textoSeguroAutomoveis(item.opcionais)}</strong></p>` : ""}
            ${item.descricao ? `<p class="auto-info-line auto-description"><span>Descricao</span><strong>${textoSeguroAutomoveis(item.descricao)}</strong></p>` : ""}
            <div class="auto-actions">
              ${contato ? `<a class="zap-link telefone-link auto-whatsapp-button" target="_blank" href="https://api.whatsapp.com/send?phone=55${contato}&text=${encodeURIComponent(whatsappTexto)}"><i class="bx bxl-whatsapp"></i> Chamar no Whats</a>` : ""}
              <span class="auto-ref-code">Ref. ${textoSeguroAutomoveis(codigoReferencia)}</span>
            </div>
          </div>
        </article>
      `;
    }).join("");
    box.querySelectorAll(".auto-seller-link[data-public-client-link]").forEach((link) => {
      link.addEventListener("click", (event) => {
        navegarParaEstabelecimentoPublico(link.dataset.publicClientLink || link.getAttribute("href")?.replace(/^#/, "") || "", event);
      });
    });
    box.querySelectorAll(".auto-card").forEach((card) => {
      const item = lista.find((entry) => String(entry.id) === String(card.dataset.autoId));
      if (!item) return;
      card.addEventListener("click", (event) => {
        if (event.__autoDetalhesHandled) return;
        if (event.target.closest("a, button")) return;
        event.__autoDetalhesHandled = true;
        registrarCliqueAutomovel("visualizacao", item);
        abrirModalDetalhesAutomovel(item);
      });
      card.querySelector(".auto-whatsapp-button")?.addEventListener("click", () => {
        registrarCliqueAutomovel("whatsapp", item);
      });
      card.querySelector(".auto-instagram-icon")?.addEventListener("click", () => {
        registrarCliqueAutomovel("instagram", item);
      });
    });
  }

  function abrirModalDetalhesAutomovel(item = {}) {
    document.querySelector(".auto-detalhes-modal")?.remove();
    const titulo = [item.marca, item.modelo].filter(Boolean).join(" ") || item.titulo || "Automovel";
    const imagens = imagensAutomovelPublico(item);
    const codigoReferencia = String(item.codRef || item.codigo || item.id || "").toUpperCase();
    const valorFormatado = item.preco ? formatarPrecoAutomoveis(item.preco) : "Consulte";
    const contato = String(item.contato || "").replace(/\D/g, "");
    const vendedor = item.vendedor || item.loja || item.clienteNome || "";
    const vendedorSlug = resolverDestinoPublicoAutomovel(item);
    const instagram = String(item.instagram || "").trim();
    const instagramUrl = instagram && instagram.startsWith("http") ? instagram : (instagram ? `https://instagram.com/${instagram.replace(/^@/, "")}` : "");
    const whatsappTexto = [
      "Ola! Vi este automovel no Ola Carlopolis e quero mais informacoes.",
      codigoReferencia ? `Referencia: ${codigoReferencia}` : "",
      `Produto: ${titulo}`,
      item.preco ? `Valor: ${valorFormatado}` : "",
      vendedor ? `Loja/Vendedor: ${vendedor}` : ""
    ].filter(Boolean).join("\n");
    const detalhes = [
      ["Marca", item.marca],
      ["Modelo", item.modelo],
      ["Condicao", item.condicao],
      ["Ano", item.ano],
      ["KM", item.km],
      ["Cambio", item.cambio],
      ["Combustivel", item.combustivel],
      ["Cor", item.cor],
      ["Motor", item.motor],
      ["Portas", item.portas],
      ["Direcao", item.direcao],
      ["Vidro eletrico", item.vidroEletrico],
      ["Trava eletrica", item.travaEletrica],
      ["Freio ABS", item.freioAbs],
      ["Freio", item.freio],
      ["Cilindrada", item.cilindrada],
      ["Partida", item.partida],
      ["Injecao eletronica", item.injecaoEletronica],
      ["Consumo medio", item.consumoMedio],
      ["Aceita troca", item.aceitaTroca],
      ["Aceita financiamento", item.aceitaFinanciamento],
      ["Documentacao", item.documentacao],
      ["Cidade", item.cidade]
    ].filter(([, value]) => value !== undefined && value !== null && String(value).trim() !== "" && String(value) !== "0");

    const modal = document.createElement("div");
    modal.className = "imovel-detalhes-modal auto-detalhes-modal";
    modal.innerHTML = `
      <section class="imovel-detalhes-dialog auto-detalhes-dialog" role="dialog" aria-modal="true" aria-label="Detalhes de ${textoSeguroAutomoveis(titulo)}">
        <button type="button" class="imovel-detalhes-fechar auto-detalhes-fechar" aria-label="Fechar detalhes" title="Fechar">&times;</button>
        <div class="imovel-detalhes-media auto-detalhes-media">
          ${imagens[0] ? `
            <div class="imovel-detalhes-galeria-track auto-detalhes-galeria-track" data-auto-detalhes-galeria-track>
              ${imagens.map((src, index) => `<img src="${textoSeguroAutomoveis(src)}" alt="Foto ${index + 1} de ${textoSeguroAutomoveis(titulo)}" loading="lazy" decoding="async">`).join("")}
            </div>
            ${imagens.length > 1 ? `
              <button type="button" class="imovel-detalhes-galeria-nav anterior" data-auto-detalhes-galeria-anterior aria-label="Foto anterior"><i class="fa-solid fa-chevron-left"></i></button>
              <button type="button" class="imovel-detalhes-galeria-nav proxima" data-auto-detalhes-galeria-proxima aria-label="Proxima foto"><i class="fa-solid fa-chevron-right"></i></button>
            ` : ""}
          ` : `<div class="imovel-detalhes-sem-foto auto-detalhes-sem-foto"><i class="fa-solid fa-car-side"></i></div>`}
        </div>
        <div class="imovel-detalhes-conteudo">
          <div class="imovel-detalhes-topo">
            <div>
              <h2>${textoSeguroAutomoveis(titulo)}</h2>
              ${vendedor ? `<p class="imovel-detalhes-endereco auto-detalhes-vendedor"><i class="fa-solid fa-store"></i><a href="#${textoSeguroAutomoveis(vendedorSlug)}" data-public-client-link="${textoSeguroAutomoveis(vendedorSlug)}">${textoSeguroAutomoveis(vendedor)}</a></p>` : ""}
            </div>
            <div class="imovel-detalhes-financeiro">
              <strong class="imovel-detalhes-valor">${textoSeguroAutomoveis(valorFormatado)}</strong>
              ${codigoReferencia ? `<span class="imovel-detalhes-referencia"><i class="fa-solid fa-hashtag"></i> Ref.: ${textoSeguroAutomoveis(codigoReferencia)}</span>` : ""}
            </div>
          </div>
          ${item.descricao || item.opcionais || item.acessorios ? `
            <section class="imovel-detalhes-descricao">
              <div class="imovel-detalhes-descricao-titulo"><i class="fa-solid fa-align-left"></i><span>Sobre o veiculo</span></div>
              ${item.descricao ? `<p>${textoSeguroAutomoveis(item.descricao)}</p>` : ""}
              ${item.acessorios ? `<p><strong>Acessorios:</strong> ${textoSeguroAutomoveis(item.acessorios)}</p>` : ""}
              ${item.opcionais ? `<p><strong>Opcionais:</strong> ${textoSeguroAutomoveis(item.opcionais)}</p>` : ""}
            </section>
          ` : ""}
          <div class="auto-detalhes-acoes">
            ${contato ? `<a class="zap-link telefone-link auto-whatsapp-button" target="_blank" href="https://api.whatsapp.com/send?phone=55${contato}&text=${encodeURIComponent(whatsappTexto)}"><i class="bx bxl-whatsapp"></i> Chamar no Whats</a>` : ""}
            ${instagramUrl ? `<a class="auto-instagram-icon auto-detalhes-instagram" target="_blank" href="${textoSeguroAutomoveis(instagramUrl)}" aria-label="Instagram de ${textoSeguroAutomoveis(vendedor || titulo)}"><i class="fa-brands fa-instagram"></i></a>` : ""}
          </div>
          <div class="imovel-detalhes-grade">
            ${detalhes.map(([label, value]) => `
              <div><span>${textoSeguroAutomoveis(label)}</span><strong>${textoSeguroAutomoveis(value)}</strong></div>
            `).join("")}
          </div>
        </div>
      </section>
    `;
    document.body.appendChild(modal);

    const fechar = () => {
      document.removeEventListener("keydown", fecharComEsc);
      modal.remove();
    };
    let indiceImagem = 0;
    let fotoContabilizadaNestaModal = false;
    const galeriaTrack = modal.querySelector("[data-auto-detalhes-galeria-track]");
    const atualizarGaleria = (novoIndice) => {
      if (!galeriaTrack || !imagens.length) return;
      indiceImagem = (novoIndice + imagens.length) % imagens.length;
      galeriaTrack.style.transform = `translateX(-${indiceImagem * 100}%)`;
    };
    const registrarFotoUmaVezNaModal = () => {
      if (fotoContabilizadaNestaModal) return;
      fotoContabilizadaNestaModal = true;
      registrarCliqueAutomovel("fotos", item);
    };
    const navegarGaleria = (direcao) => {
      registrarFotoUmaVezNaModal();
      atualizarGaleria(indiceImagem + direcao);
    };
    const fecharComEsc = (event) => {
      if (event.key === "Escape") fechar();
      if (event.key === "ArrowLeft" && imagens.length > 1) navegarGaleria(-1);
      if (event.key === "ArrowRight" && imagens.length > 1) navegarGaleria(1);
    };
    modal.querySelector(".auto-detalhes-fechar")?.addEventListener("click", fechar);
    modal.addEventListener("click", (event) => {
      if (event.target === modal) fechar();
    });
    modal.querySelector("[data-auto-detalhes-galeria-anterior]")?.addEventListener("click", () => navegarGaleria(-1));
    modal.querySelector("[data-auto-detalhes-galeria-proxima]")?.addEventListener("click", () => navegarGaleria(1));
    galeriaTrack?.addEventListener("click", () => {
      registrarFotoUmaVezNaModal();
      fechar();
      abrirGaleriaAutomovel(imagens, indiceImagem, titulo);
    });
    modal.querySelector(".auto-whatsapp-button")?.addEventListener("click", () => registrarCliqueAutomovel("whatsapp", item));
    modal.querySelector(".auto-detalhes-instagram")?.addEventListener("click", () => registrarCliqueAutomovel("instagram", item));
    document.addEventListener("keydown", fecharComEsc);
    modal.querySelector(".auto-detalhes-fechar")?.focus();
  }

  function configurarDetalhesAutomoveisEmBox(box, obterLista) {
    if (!box || box.dataset.autoDetalhesDelegado === "1") return;
    box.dataset.autoDetalhesDelegado = "1";
    const abrirDetalhesAutomovelDelegado = (event) => {
      if (event.__autoDetalhesHandled) return;
      const trigger = event.target.closest?.("[data-auto-detalhes]");
      if (!trigger || !box.contains(trigger)) return;
      if (event.type === "keydown" && !["Enter", " "].includes(event.key)) return;
      event.preventDefault();
      event.stopPropagation();
      const itemId = trigger.dataset.autoDetalhes || "";
      const lista = typeof obterLista === "function" ? obterLista() : (obterLista || []);
      const item = lista.find((entry) => String(entry.id) === String(itemId))
        || (Array.isArray(window.__automoveisCache) ? window.__automoveisCache.find((entry) => String(entry.id) === String(itemId)) : null);
      if (!item) return;
      event.__autoDetalhesHandled = true;
      registrarCliqueAutomovel("visualizacao", item);
      abrirModalDetalhesAutomovel(item);
    };
    box.addEventListener("click", abrirDetalhesAutomovelDelegado);
    box.addEventListener("keydown", abrirDetalhesAutomovelDelegado);
  }

  function registrarCliqueAutomovel(tipo, item = {}) {
    const responsavel = item.clienteId || item.estabelecimentoId || item.clienteNome || item.vendedor || item.loja;
    if (!responsavel) return Promise.resolve();
    return registrarCliqueBotao(`veiculo_${tipo}`, responsavel, "veiculos", {
      veiculoId: item.id || "",
      tituloConteudo: [item.marca, item.modelo, item.ano].filter(Boolean).join(" "),
      codRef: item.codRef || item.codigo || item.id || "",
      clienteId: item.clienteId || "",
      vendedor: item.vendedor || item.loja || ""
    });
  }

  function configurarGaleriasAutomoveis(box) {
    // Mantido para compatibilidade: o card agora abre detalhes; a galeria abre dentro da modal.
  }

  function lerImagensGaleriaAutomovel(media) {
    try {
      return JSON.parse(decodeURIComponent(media.dataset.autoGallery || "[]")).filter(Boolean);
    } catch (error) {
      return [];
    }
  }

  function abrirGaleriaAutomovel(imagens, inicio = 0, titulo = "Automovel") {
    if (!imagens.length) return;
    let indice = Math.max(0, Math.min(inicio, imagens.length - 1));
    document.querySelector(".auto-gallery-modal")?.remove();
    const modal = document.createElement("div");
    modal.className = "auto-gallery-modal";
    modal.innerHTML = `
      <div class="auto-gallery-modal-box" role="dialog" aria-label="${textoSeguroAutomoveis(titulo)}">
        <button class="auto-gallery-modal-close" type="button" aria-label="Fechar"><i class="fa-solid fa-xmark"></i></button>
        <button class="auto-gallery-modal-nav auto-gallery-modal-prev" type="button" aria-label="Imagem anterior"><i class="fa-solid fa-chevron-left"></i></button>
        <img src="" alt="${textoSeguroAutomoveis(titulo)}">
        <button class="auto-gallery-modal-nav auto-gallery-modal-next" type="button" aria-label="Proxima imagem"><i class="fa-solid fa-chevron-right"></i></button>
        <span class="auto-gallery-modal-count"></span>
      </div>
    `;
    const img = modal.querySelector("img");
    const count = modal.querySelector(".auto-gallery-modal-count");
    const render = () => {
      img.src = imagens[indice];
      count.textContent = `${indice + 1}/${imagens.length}`;
    };
    const mover = (passo) => {
      indice = (indice + passo + imagens.length) % imagens.length;
      render();
    };
    modal.querySelector(".auto-gallery-modal-close")?.addEventListener("click", () => modal.remove());
    modal.querySelector(".auto-gallery-modal-prev")?.addEventListener("click", (event) => {
      event.stopPropagation();
      mover(-1);
    });
    modal.querySelector(".auto-gallery-modal-next")?.addEventListener("click", (event) => {
      event.stopPropagation();
      mover(1);
    });
    modal.addEventListener("click", (event) => {
      if (event.target === modal) modal.remove();
    });
    let toqueInicialX = 0;
    modal.addEventListener("touchstart", (event) => {
      toqueInicialX = event.changedTouches?.[0]?.clientX || 0;
    }, { passive: true });
    modal.addEventListener("touchend", (event) => {
      const toqueFinalX = event.changedTouches?.[0]?.clientX || 0;
      const delta = toqueFinalX - toqueInicialX;
      if (Math.abs(delta) > 45) mover(delta > 0 ? -1 : 1);
    }, { passive: true });
    document.addEventListener("keydown", function fecharOuMover(event) {
      if (!document.body.contains(modal)) {
        document.removeEventListener("keydown", fecharOuMover);
        return;
      }
      if (event.key === "Escape") modal.remove();
      if (event.key === "ArrowLeft") mover(-1);
      if (event.key === "ArrowRight") mover(1);
    });
    render();
    document.body.appendChild(modal);
  }

  function prepararNavegacaoMenuEspecial() {
    document.getElementById("novidades")?.classList.add("hidden");
    document.querySelector(".content_area")?.classList.remove("hidden");
    const sidebarEl = document.querySelector(".sidebar");
    const overlayEl = document.getElementById("overlay");
    sidebarEl?.classList.remove("open");
    if (window.innerWidth < 768) sidebarEl?.classList.add("close");
    overlayEl?.classList.remove("active");
    document.querySelectorAll(".submenu_item").forEach((item) => item.classList.remove("show_submenu"));
    document.querySelectorAll(".submenu").forEach((sub) => {
      sub.style.display = "none";
    });
    const busca = document.getElementById("searchTopbar") || document.getElementById("searchSidebar");
    const clear = document.getElementById("clearTopbarSearch") || document.getElementById("clearSearch");
    if (busca) busca.value = "";
    if (clear) clear.style.display = "none";
  }

  async function carregarAutomoveisFirebase(options = {}) {
    const deveReidratarLojas = options.reidratarLojas !== false;
    const dbAdmin = await esperarFirebaseDatabase();
    if (!dbAdmin) return window.__automoveisCache || [];
    const timeout = new Promise((_, reject) => {
      setTimeout(() => reject(new Error("Tempo limite ao carregar automoveis.")), 6000);
    });
    const [legacySnap, novoSnap] = await Promise.race([
      Promise.all([
        dbAdmin.ref("conteudo/veiculos").once("value"),
        dbAdmin.ref("conteudosInformativos/automoveis").once("value")
      ]),
      timeout
    ]);
    const lista = [];
    legacySnap.forEach((child) => {
      lista.push(automovelDeRegistro(child.val() || {}, child.key));
      return false;
    });
    novoSnap.forEach((child) => {
      lista.push(automovelDeRegistro(child.val() || {}, child.key));
      return false;
    });
    const ativos = lista.filter((item) => item.status !== "inativo");
    window.__automoveisCache = ativos;
    if (deveReidratarLojas && typeof hidratarAbasItensEstabelecimentoPublico === "function" && Array.isArray(window.__lojaItensUltimosEstabelecimentos)) {
      setTimeout(() => {
        hidratarAbasItensEstabelecimentoPublico(document.querySelector(".content_area"), window.__lojaItensUltimosEstabelecimentos)
          .catch((error) => console.warn("Nao foi possivel reidratar abas de veiculos.", error));
      }, 0);
    }
    return ativos;
  }

  async function mostrarAutomoveis() {
    if (location.hash !== "#automoveis") location.hash = "#automoveis";
    const area = document.querySelector(".content_area");
    if (!area) return;

    area.innerHTML = `
      <section class="imoveis-wrap automoveis-page">
        <h2 class="highlighted"><span><i class="fa-solid fa-car"></i> AUTOMOVEIS</span></h2>
        <aside id="filtrosAutomoveis" class="im-filtros painel-filtros auto-filter-collapsed">
          <div class="topbar">
            <button id="autoToggleFiltros" class="auto-filter-toggle" type="button" aria-expanded="false">
              <i class="fa-solid fa-sliders"></i>
              <span>Filtro</span>
              <i class="fa-solid fa-chevron-down auto-filter-chevron"></i>
            </button>
            <span id="autoTotalDisponiveis" class="auto-total-disponiveis" aria-label="Total de automoveis">
              <i class="fa-solid fa-car-side"></i>
              <strong>...</strong>
            </span>
            <label class="switch auto-cards-switch" title="Mostrar automoveis em cards menores">
              <input type="checkbox" id="autoModoCards" ${window.__automoveisModoCards ? "checked" : ""}>
              <span class="track"><span class="thumb"></span></span>
              <span>Cards</span>
            </label>
          </div>
          <div class="grid-filtros">
            <div class="campo"><label>Tipo</label><select id="autoFiltroTipo"><option value="">Todos</option></select></div>
            <div class="campo"><label>Marca</label><select id="autoFiltroMarca"><option value="">Todas</option></select></div>
            <div class="campo"><label>Modelo</label><select id="autoFiltroModelo"><option value="">Todos</option></select></div>
            <div class="campo"><label>Ano</label><input id="autoFiltroAno" placeholder="Ex: 2020"></div>
            <div class="campo"><label>Valor ate</label><input id="autoFiltroValor" placeholder="Ex: 50000"></div>
            <div class="campo"><label>Vendedor</label><select id="autoFiltroVendedor"><option value="">Todos</option></select></div>
            <div class="campo"><label>Novo/usado</label><select id="autoFiltroCondicao"><option value="">Todos</option></select></div>
            <div class="campo"><label>KM ate</label><input id="autoFiltroKm" placeholder="Ex: 80000"></div>
            <div class="campo"><label>Combustivel</label><select id="autoFiltroCombustivel"><option value="">Todos</option></select></div>
            <div class="campo"><label>Cambio</label><select id="autoFiltroCambio"><option value="">Todos</option></select></div>
            <div class="campo"><label>Busca geral</label><input id="autoFiltroBusca" placeholder="Marca, modelo, opcionais..."></div>
          </div>
        </aside>
        <div id="automoveisLista" class="im-grid">
          <div class="list-meta">Carregando automoveis...</div>
        </div>
      </section>
    `;

    const box = document.getElementById("automoveisLista");
    const filtroBox = document.getElementById("filtrosAutomoveis");
    const toggleFiltros = document.getElementById("autoToggleFiltros");
    const totalDisponiveis = document.getElementById("autoTotalDisponiveis");
    let lista = Array.isArray(window.__automoveisCache) ? window.__automoveisCache : [];

    configurarDetalhesAutomoveisEmBox(box, () => lista);

    const preencherSelect = (id, campo) => {
      const el = document.getElementById(id);
      if (!el) return;
      const primeiraOpcao = el.querySelector("option")?.outerHTML || `<option value="">Todos</option>`;
      el.innerHTML = primeiraOpcao + opcoesAutomoveis(lista, campo);
    };

    const preencherFiltros = () => {
      preencherSelect("autoFiltroTipo", "tipo");
      preencherSelect("autoFiltroMarca", "marca");
      preencherSelect("autoFiltroModelo", "modelo");
      preencherSelect("autoFiltroCondicao", "condicao");
      preencherSelect("autoFiltroCombustivel", "combustivel");
      preencherSelect("autoFiltroCambio", "cambio");
      preencherSelect("autoFiltroVendedor", "vendedor");
    };

    const atualizarTotalAutomoveis = (totalFiltrado = lista.length) => {
      const labelContador = `automovel${totalFiltrado === 1 ? "" : "s"}`;
      if (totalDisponiveis) {
        totalDisponiveis.setAttribute("aria-label", `${totalFiltrado} ${labelContador}`);
        totalDisponiveis.innerHTML = `
          <i class="fa-solid fa-car-side" aria-hidden="true"></i>
          <strong>${totalFiltrado}</strong>
          <span class="auto-total-label">${labelContador}</span>
        `;
      }
    };

    const aplicarModoCards = () => {
      const ativo = Boolean(document.getElementById("autoModoCards")?.checked);
      window.__automoveisModoCards = ativo;
      document.querySelector(".automoveis-page")?.classList.toggle("auto-cards-mode", ativo);
      box?.classList.toggle("auto-cards-grid", ativo);
    };

    const aplicar = () => {
      if (!box) return;
      aplicarModoCards();
      if (!lista.length) {
        box.innerHTML = `<div class="list-meta">Carregando automoveis...</div>`;
        return;
      }
      const filtros = {
        tipo: document.getElementById("autoFiltroTipo")?.value || "",
        marca: document.getElementById("autoFiltroMarca")?.value || "",
        modelo: document.getElementById("autoFiltroModelo")?.value || "",
        ano: normalizarTextoAutomoveis(document.getElementById("autoFiltroAno")?.value || ""),
        valor: numeroAutomoveis(document.getElementById("autoFiltroValor")?.value || ""),
        vendedor: document.getElementById("autoFiltroVendedor")?.value || "",
        condicao: document.getElementById("autoFiltroCondicao")?.value || "",
        km: numeroAutomoveis(document.getElementById("autoFiltroKm")?.value || ""),
        combustivel: document.getElementById("autoFiltroCombustivel")?.value || "",
        cambio: document.getElementById("autoFiltroCambio")?.value || "",
        busca: normalizarTextoAutomoveis(document.getElementById("autoFiltroBusca")?.value || "")
      };
      const filtrados = lista.filter((item) => {
        const hay = normalizarTextoAutomoveis(`${item.tipo} ${item.marca} ${item.modelo} ${item.ano} ${item.preco} ${item.vendedor || item.loja} ${item.condicao} ${item.km} ${item.combustivel} ${item.cambio} ${item.cor} ${item.cidade} ${item.opcionais} ${item.descricao}`);
        if (filtros.tipo && item.tipo !== filtros.tipo) return false;
        if (filtros.marca && item.marca !== filtros.marca) return false;
        if (filtros.modelo && item.modelo !== filtros.modelo) return false;
        if (filtros.ano && !normalizarTextoAutomoveis(item.ano).includes(filtros.ano)) return false;
        if (filtros.valor && numeroAutomoveis(item.preco) > filtros.valor) return false;
        if (filtros.vendedor && (item.vendedor || item.loja) !== filtros.vendedor) return false;
        if (filtros.condicao && item.condicao !== filtros.condicao) return false;
        if (filtros.km && numeroAutomoveis(item.km) > filtros.km) return false;
        if (filtros.combustivel && item.combustivel !== filtros.combustivel) return false;
        if (filtros.cambio && item.cambio !== filtros.cambio) return false;
        if (filtros.busca && !hay.includes(filtros.busca)) return false;
        return true;
      });
      atualizarTotalAutomoveis(filtrados.length);
      renderAutomoveisCards(filtrados, box);
    };

    toggleFiltros?.addEventListener("click", () => {
      const expanded = filtroBox?.classList.toggle("auto-filter-collapsed") === false;
      toggleFiltros.setAttribute("aria-expanded", expanded ? "true" : "false");
    });
    document.getElementById("autoModoCards")?.addEventListener("change", aplicarModoCards);
    document.querySelectorAll("#filtrosAutomoveis input:not(#autoModoCards), #filtrosAutomoveis select").forEach((el) => {
      el.addEventListener("input", aplicar);
      el.addEventListener("change", aplicar);
    });
    aplicarModoCards();
    atualizarTotalAutomoveis();

    if (lista.length) {
      preencherFiltros();
      aplicar();
    }

    try {
      filtroBox?.classList.add("auto-filter-loading");
      lista = await carregarAutomoveisFirebase();
    } catch (error) {
      console.warn("Nao foi possivel carregar automoveis.", error);
      if (!lista.length) box.innerHTML = `<div class="list-meta">Nao foi possivel carregar os automoveis agora.</div>`;
      return;
    } finally {
      filtroBox?.classList.remove("auto-filter-loading");
    }
    if (!lista.length) {
      atualizarTotalAutomoveis();
      box.innerHTML = `<div class="list-meta">Nenhum automovel anunciado no momento.</div>`;
      return;
    }

    preencherFiltros();
    aplicar();
  }

  async function hidratarAbasItensEstabelecimentoPublico(root, estabelecimentos = [], options = {}) {
    const area = root || document;
    const cards = [...area.querySelectorAll("li[data-id], li[id]")];
    if (!cards.length) return;
    const carregarRemoto = options.carregarRemoto !== false;
    const atualizar = options.atualizar === true;

    const estabelecimentosPorChave = new Map();
    estabelecimentos.forEach((est) => {
      chavesEstabelecimentoPublico(est).forEach((chave) => estabelecimentosPorChave.set(chave, est));
    });
    const encontrarEstabelecimentoPorSlug = (slug) => {
      const chaveCard = normalizeName(slug);
      if (!chaveCard) return null;
      const direto = estabelecimentosPorChave.get(chaveCard);
      if (direto) return direto;
      return estabelecimentos.find((est) => chavesEstabelecimentoPublico(est).some((chave) => (
        chave.length >= 4
        && chaveCard.length >= 4
        && (chave.includes(chaveCard) || chaveCard.includes(chave))
      ))) || null;
    };

    const autos = Array.isArray(options.autos) ? options.autos : (window.__automoveisCache || []);
    const imoveis = Array.isArray(options.imoveis) ? options.imoveis : (window.__imoveisPublicosCache || []);
    await carregarModulosClientesPublicos();
    if (carregarRemoto) {
      carregarAutomoveisFirebase({ reidratarLojas: false })
        .then((lista) => {
          hidratarAbasItensEstabelecimentoPublico(area, estabelecimentos, {
            autos: lista,
            imoveis: window.__imoveisPublicosCache || imoveis,
            carregarRemoto: false,
            atualizar: true
          }).catch((error) => console.warn("Nao foi possivel atualizar aba de veiculos.", error));
        })
        .catch((error) => console.warn("Nao foi possivel carregar veiculos da loja.", error));
      montarListaImoveisPublica()
        .then((lista) => {
          window.__imoveisPublicosCache = lista;
          hidratarAbasItensEstabelecimentoPublico(area, estabelecimentos, {
            autos: window.__automoveisCache || autos,
            imoveis: lista,
            carregarRemoto: false,
            atualizar: true
          }).catch((error) => console.warn("Nao foi possivel atualizar aba de imoveis.", error));
        })
        .catch((error) => console.warn("Nao foi possivel carregar imoveis da loja.", error));
    }

    const adicionarAba = (li, slug, tipo, label, icon, renderizar, count = 0) => {
      const nav = li.querySelector(".abas-nav");
      const conteudo = li.querySelector(".abas-conteudo");
      if (!nav || !conteudo) return false;
      const targetId = `${tipo}-${slug}`;
      const jaExiste = Boolean(nav.querySelector(`[data-target="${targetId}"]`));
      if (!jaExiste) {
        const tone = tipo === "promocoes" ? "orange" : (tipo === "produtos" || tipo === "cardapio" ? "purple" : (tipo === "fotos" ? "green" : "blue"));
        nav.insertAdjacentHTML("beforeend", renderAbaClientePublica({
          target: targetId,
          label,
          icon: `fa-solid ${icon}`,
          count,
          tone
        }));
        ordenarAbasClientePublica(nav);
      }
      let pane = conteudo.querySelector(`#${CSS.escape(targetId)}`);
      if (!pane) {
        conteudo.insertAdjacentHTML("beforeend", `<div class="aba loja-itens-aba" id="${targetId}" style="display:none"></div>`);
        pane = conteudo.querySelector(`#${CSS.escape(targetId)}`);
      }
      renderizar(pane);
      return !jaExiste;
    };

    cards.forEach((li) => {
      const slug = normalizeName(li.dataset.id || li.id || "");
      const est = encontrarEstabelecimentoPorSlug(slug);
      if (!est || (li.dataset.lojaItensHidratados === "1" && !atualizar)) return;
      let abasInseridas = false;

      const veiculos = automoveisDoEstabelecimentoPublico(est, autos || []);
      const imoveisDoEst = (imoveis || []).filter((item) => item.status !== "inativo" && item.ativo !== false && itemPertenceAoEstabelecimentoPublico(item, est));
      const produtos = produtosDoEstabelecimentoPublico(est);
      const promocoes = promocoesDoEstabelecimentoPublico(est);
      const deveMostrarAbaVeiculos = veiculos.length && moduloClientePublicoAtivo(est, "veiculos");
      const deveMostrarAbaImoveis = imoveisDoEst.length && moduloClientePublicoAtivo(est, "imoveis");
      const deveMostrarAbaProdutos = produtos.length && moduloClientePublicoAtivo(est, "produtos");
      const deveMostrarAbaPromocoes = promocoes.length && moduloClientePublicoAtivo(est, "promocoes");
      const temAbaItens = Boolean(li.querySelector(
        `[data-target="veiculos-${slug}"],[data-target="imoveis-${slug}"],[data-target="produtos-${slug}"],[data-target="promocoes-${slug}"]`
      ));

      if (deveMostrarAbaVeiculos) {
        abasInseridas = adicionarAba(li, slug, "veiculos", "Veiculos", "fa-car-side", (pane) => {
          pane.innerHTML = `<section class="imoveis-wrap automoveis-page auto-cards-mode loja-itens-wrap"><div class="im-grid auto-cards-grid loja-itens-grid loja-veiculos-grid"></div></section>`;
          const box = pane.querySelector(".loja-itens-grid");
          if (veiculos.length) {
            renderAutomoveisCards(veiculos, box);
            configurarDetalhesAutomoveisEmBox(box, () => veiculos);
            box.querySelectorAll("[data-auto-detalhes]").forEach((trigger) => {
              trigger.addEventListener("click", (event) => {
                if (event.__autoDetalhesHandled) return;
                event.preventDefault();
                event.stopPropagation();
                const item = veiculos.find((auto) => String(auto.id) === String(trigger.dataset.autoDetalhes));
                if (!item) return;
                event.__autoDetalhesHandled = true;
                registrarCliqueAutomovel("visualizacao", item);
                abrirModalDetalhesAutomovel(item);
              });
            });
          } else if (box) {
            box.innerHTML = `<div class="list-meta">Carregando veiculos desta loja...</div>`;
          }
        }, veiculos.length) || abasInseridas;
      }

      if (deveMostrarAbaImoveis) {
        abasInseridas = adicionarAba(li, slug, "imoveis", "Imoveis", "fa-house", (pane) => {
          pane.innerHTML = `<section class="imoveis-wrap im-cards-mode loja-itens-wrap"><div class="im-grid loja-itens-grid"></div></section>`;
          renderImoveisCardsEstabelecimento(imoveisDoEst, pane.querySelector(".loja-itens-grid"));
        }, imoveisDoEst.length) || abasInseridas;
      }

      if (deveMostrarAbaProdutos) {
        abasInseridas = adicionarAba(li, slug, "produtos", "Produtos", "fa-box-open", (pane) => {
          pane.innerHTML = `<section class="loja-itens-wrap loja-produtos-wrap auto-cards-mode"><div class="loja-produtos-grid loja-cards-grid loja-itens-grid">${produtos.map((item) => renderProdutoCardEstabelecimento(item, "produto")).join("")}</div></section>`;
          pane.querySelectorAll("[data-loja-produto]").forEach((card) => {
            card.addEventListener("click", (event) => {
              if (event.__lojaProdutoHandled) return;
              if (event.target.closest("a, button")) return;
              const item = produtos.find((produto) => String(produto.id) === String(card.dataset.lojaProduto));
              if (item) {
                event.__lojaProdutoHandled = true;
                abrirModalProdutoEstabelecimento(item, "Produto");
              }
            });
          });
        }, produtos.length) || abasInseridas;
      }

      if (deveMostrarAbaPromocoes) {
        abasInseridas = adicionarAba(li, slug, "promocoes", "Promocoes", "fa-tags", (pane) => {
          const promocoesUnicas = deduplicarPromocoesMesmoEstabelecimentoPublico(promocoes);
          const contatoPromocaoPadrao = getPrimeiroContato(est.contact || est.contato || est.whatsapp || est.telefone || "") || "";
          const itens = promocoesUnicas.map((promo) => ({
            id: promo.id,
            titulo: promo.titulo,
            descricao: promo.descricao || promo.obs,
            preco: promo.preco,
            precoAntigo: promo.precoAntigo || promo.precoReal || promo.valorReal || promo.precoOriginal || "",
            imagem: promo.imagem,
            imagens: promo.imagens || (promo.imagem ? [promo.imagem] : []),
            validadeFim: promo.validadeFim || "",
            desconto: promo.desconto || "",
            entregaRetirada: promo.entregaRetirada || "",
            observacoes: [promo.validadeFim ? `Valido ate ${promo.validadeFim}` : "", promo.desconto ? `Desconto: ${promo.desconto}` : ""].filter(Boolean).join(" | "),
            categoria: "Promocao",
            contato: getPrimeiroContato(promo.contato || promo.contact || promo.whatsapp || "") || contatoPromocaoPadrao,
            whatsapp: promo.whatsapp || promo.contato || promo.contact || contatoPromocaoPadrao,
            telefone: promo.telefone || est.telefone || ""
          }));
          pane.innerHTML = `<section class="loja-itens-wrap loja-promocoes-wrap promo-city-screen"><div class="loja-produtos-grid loja-cards-grid">${itens.map((item) => renderProdutoCardEstabelecimento(item, "promocao")).join("")}</div></section>`;
          pane.querySelectorAll("[data-loja-produto]").forEach((card) => {
            card.addEventListener("click", (event) => {
              if (event.__lojaProdutoHandled) return;
              if (event.target.closest("a, button")) return;
              const item = itens.find((produto) => String(produto.id) === String(card.dataset.lojaProduto));
              if (item) {
                event.__lojaProdutoHandled = true;
                abrirModalProdutoEstabelecimento(item, "Promocao");
              }
            });
          });
        }, deduplicarPromocoesMesmoEstabelecimentoPublico(promocoes).length) || abasInseridas;
      }

      const veiculosPendentes = deveMostrarAbaVeiculos && !veiculos.length;
      if ((abasInseridas || temAbaItens) && !veiculosPendentes) {
        li.dataset.lojaItensHidratados = "1";
        moveTabSlider(li.querySelector(".abas-nav"));
      } else if (abasInseridas) {
        moveTabSlider(li.querySelector(".abas-nav"));
      }
    });
  }

  function estabelecimentosVisiveisParaAbasPublicas(root = document) {
    const area = root || document;
    const ids = new Set([...area.querySelectorAll("li[data-id], li[id]")]
      .map((li) => normalizeName(li.dataset.id || li.id || ""))
      .filter(Boolean));
    if (!ids.size) return [];
    const encontrados = [];
    (categories || []).forEach((cat) => {
      (cat.establishments || []).forEach((est) => {
        const chaves = chavesEstabelecimentoPublico(est);
        const combina = chaves.some((chave) => ids.has(chave) || [...ids].some((id) => (
          chave.length >= 4
          && id.length >= 4
          && (chave.includes(id) || id.includes(chave))
        )));
        if (!combina) return;
        est.__categoriaPublica = cat.title || est.__categoriaPublica || "";
        encontrados.push(est);
      });
    });
    return encontrados;
  }

  let lojaItensAutoHydrateTimer = null;
  function agendarHidratacaoAbasItensPublicas(root = document, delay = 120) {
    if (lojaItensAutoHydrateTimer) clearTimeout(lojaItensAutoHydrateTimer);
    lojaItensAutoHydrateTimer = setTimeout(() => {
      const area = root?.querySelector?.(".content_area") || document.querySelector(".content_area") || root || document;
      const estabelecimentos = estabelecimentosVisiveisParaAbasPublicas(area);
      if (!estabelecimentos.length) return;
      const carregarRemoto = !window.__lojaItensAutoHydrateRemoteStarted;
      window.__lojaItensAutoHydrateRemoteStarted = true;
      window.__lojaItensUltimosEstabelecimentos = estabelecimentos;
      hidratarAbasItensEstabelecimentoPublico(area, estabelecimentos, { carregarRemoto, atualizar: true })
        .catch((error) => console.warn("Nao foi possivel hidratar abas de itens visiveis.", error));
    }, delay);
  }

