// === util: setar texto seguro no DOM ===
function setTexto(sel, val) {
  const el = document.querySelector(sel);
  if (el) el.textContent = (val ?? '—');
}

async function carregarDadosRepresa() {
  const btn = document.querySelector('.btn-refresh');
  const originalText = btn ? btn.innerHTML : null;

  try {
    if (btn) {
      btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Atualizando...';
      btn.disabled = true;
    }

    // 1) Tenta a API própria (serverless, sem CORS no cliente)
    const r = await fetch(API_REPRESA, { cache: 'no-store' });
    const data = await r.json();

    if (!data?.success) throw new Error('API retornou sem sucesso');
    if (dadosRepresaParecemInvalidos(data)) throw new Error('API retornou o nivel maximo da CTG em vez da medicao atual');

    const cotaAtual = data.cotaAtual ?? data.cota ?? data.nivel ?? data.nivel_m ?? '—';
    const volumeUtil = data.volumeUtil ?? data.volume ?? data.volumeUtilPct ?? data.volume_util_pct ?? '—';
    const vazaoAfluente = data.vazaoAfluente ?? data.afluente ?? '—';
    const vazaoDefluente = data.vazaoDefluente ?? data.defluente ?? data.defluencia_m3s ?? '—';
    const atualizadoEm = data.atualizadoEm || data.ultimaAtualizacao || Date.now();

    // Preenche UI principal
    setTexto('#cotaAtual', cotaAtual);
    setTexto('#volumeUtil', volumeUtil);
    setTexto('#vazaoAfluente', vazaoAfluente);
    setTexto('#vazaoDefluente', vazaoDefluente);
    setTexto('#ultimaAtualizacao',
      new Date(atualizadoEm).toLocaleString('pt-BR'));

    // Exibe fonte e, se existir UI “NR” (carrossel da home), também preenche
    setTexto('#fonteDados', `Fonte: ${data.fonte || 'CTG Brasil'}`);
    setTexto('#statusDadosRepresa', data.horarioReferencia
      ? `Dados carregados da fonte oficial - medicao das ${data.horarioReferencia}.`
      : 'Dados carregados da fonte oficial.');
    setTexto('#nr-cota', cotaAtual);
    setTexto('#nr-volume', volumeUtil);
    setTexto('#nr-data', new Date(atualizadoEm).toLocaleDateString('pt-BR'));
    const registroAtual = await salvarHistoricoRepresa(data);
    await renderHistoricoRepresa(document.getElementById('represaHistoricoPeriodo')?.value || '30', registroAtual);

    // Destaque visual
    if (typeof destacarMudancas === 'function') destacarMudancas();
  } catch (err) {
    console.error('Erro ao carregar dados:', err);

    // 2) Fallback: tenta seu leitor atual (se quiser manter)
    try {
      if (typeof buscarCTGviaJina === 'function') {
        const dados = await buscarCTGviaJina(); // mantém seu leitor como 2ª opção
        setTexto('#cotaAtual', dados.cota);
        setTexto('#volumeUtil', dados.volume);
        setTexto('#vazaoAfluente', dados.vazaoAfluente ?? '—');
        setTexto('#vazaoDefluente', dados.vazaoDefluente ?? '—');
        setTexto('#ultimaAtualizacao', dados.atualizacao);
        setTexto('#fonteDados', `Fonte: ${dados.fonte}`);
        setTexto('#statusDadosRepresa', 'Dados carregados da página oficial da CTG.');
        setTexto('#nr-cota', dados.cota);
        setTexto('#nr-volume', dados.volume);
        setTexto('#nr-data', dados.atualizacao);
        const registroAtual = await salvarHistoricoRepresa({
          cotaAtual: dados.cota,
          volumeUtil: dados.volume,
          vazaoAfluente: dados.vazaoAfluente,
          vazaoDefluente: dados.vazaoDefluente,
          atualizadoEm: Date.now(),
          fonte: dados.fonte
        });
        await renderHistoricoRepresa(document.getElementById('represaHistoricoPeriodo')?.value || '30', registroAtual);
        if (typeof destacarMudancas === 'function') destacarMudancas();
        return;
      }
      throw new Error('Sem fallback disponível');
    } catch (e2) {
      console.error('Fallback falhou:', e2);
      if (typeof mostrarErroCarregamento === 'function') mostrarErroCarregamento();
    }
  } finally {
    if (btn) {
      btn.innerHTML = originalText;
      btn.disabled = false;
    }
  }
}



